import React, { useMemo } from 'react';
import type { Schedule, DayOfWeek, ScheduledBartender } from '../types';

interface ScheduleViewProps {
  schedule: Schedule;
  startDate?: string;
}

const DAY_ORDER: DayOfWeek[] = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun', 'Sun_Night'];
const FLOOR_ORDER = ['Rooftop', 'Hip Hop', "2010's", "2000's"];

const ScheduleView: React.FC<ScheduleViewProps> = ({ schedule, startDate }) => {
  // Pre-process the schedule data to avoid heavy logic inside the render loops
  const groupedData = useMemo(() => {
    const weeks = [1, 2, 3, 4];
    return weeks.map(week => {
      const weekSchedule = schedule.filter(s => s.week === week);
      if (weekSchedule.length === 0) return null;

      const grid: Record<string, Record<string, ScheduledBartender[]>> = {};
      const days = [...new Set<DayOfWeek>(weekSchedule.map(entry => entry.day))].sort((a, b) => DAY_ORDER.indexOf(a) - DAY_ORDER.indexOf(b));

      weekSchedule.forEach(entry => {
        const key = `${entry.floor} / ${entry.bar}`;
        if (!grid[key]) grid[key] = {};
        grid[key][entry.day] = entry.bartenders;
      });

      const uniqueKeys = Object.keys(grid).sort((a, b) => {
          const [floorA, barA] = a.split(' / ');
          const [floorB, barB] = b.split(' / ');
          const indexA = FLOOR_ORDER.indexOf(floorA);
          const indexB = FLOOR_ORDER.indexOf(floorB);
          if (indexA !== indexB) return (indexA === -1 ? 1 : indexB === -1 ? -1 : indexA - indexB);
          return barA.localeCompare(barB);
      });

      return { week, grid, days, uniqueKeys };
    }).filter(w => w !== null);
  }, [schedule]);

  const getFormattedDate = (start: string, day: DayOfWeek, weekIndex: number) => {
    // Append T00:00:00 to force local time interpretation
    const date = new Date(start + 'T00:00:00');
    const dayIndex = DAY_ORDER.indexOf(day);
    // Sun and Sun_Night use the same offset
    const offset = dayIndex === 7 ? 6 : dayIndex; 
    date.setDate(date.getDate() + offset + ((weekIndex - 1) * 7));
    return `${day.replace('_', ' ')} ${date.getMonth() + 1}/${date.getDate()}`;
  }

  return (
    <div className="space-y-8">
      {groupedData.map(({ week, grid, days, uniqueKeys }) => (
        <div key={week} className="animate-fadeIn">
          <div className="flex items-center gap-3 mb-4">
             <h3 className="text-xl font-bold text-white bg-indigo-600/20 px-4 py-1 rounded-full border border-indigo-500/30">Week {week}</h3>
             <div className="h-[1px] flex-1 bg-slate-700/50"></div>
          </div>
          <div className="overflow-x-auto rounded-xl border border-slate-700/50 bg-slate-800/30 shadow-inner">
            <table className="w-full min-w-[900px] text-sm text-left">
              <thead className="text-xs text-slate-400 uppercase bg-slate-900/50">
                <tr>
                  <th className="px-6 py-4 font-bold border-r border-slate-700/50">Shift</th>
                  {days.map(day => (
                    <th key={day} className="px-6 py-4 text-center">
                      {startDate ? getFormattedDate(startDate, day as DayOfWeek, week) : day.replace('_', ' ')}
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-700/50">
                {uniqueKeys.map((key) => {
                  const [floor, bar] = key.split(' / ');
                  return (
                    <tr key={key} className="hover:bg-slate-700/20 transition-colors group">
                      <td className="px-6 py-4 border-r border-slate-700/50">
                        <div className="font-bold text-slate-200 group-hover:text-indigo-300 transition-colors">{floor}</div>
                        <div className="text-[10px] uppercase tracking-wider text-slate-500 font-medium">{bar}</div>
                      </td>
                      {days.map(day => {
                        const bartenders = grid[key][day] || [];
                        return (
                          <td key={day} className="px-6 py-4 text-center align-top">
                            {bartenders.length > 0 ? (
                              <div className="space-y-1">
                                {bartenders.map((b, idx) => (
                                  <div key={idx} className="flex flex-col items-center">
                                    <span className={`font-semibold ${b.role === 'Fixed' ? 'text-amber-400' : 'text-slate-200'}`}>
                                      {b.name}
                                    </span>
                                    {b.role && (
                                      <span className={`text-[9px] uppercase font-bold px-1.5 py-0.5 rounded ${b.role === 'Fixed' ? 'bg-amber-900/40 text-amber-500' : 'bg-indigo-900/40 text-indigo-400'}`}>
                                        {b.role}
                                      </span>
                                    )}
                                  </div>
                                ))}
                              </div>
                            ) : (
                              <span className="text-[10px] font-bold text-slate-700 uppercase tracking-widest bg-slate-800/40 px-3 py-1.5 rounded-md border border-slate-700/30">Open</span>
                            )}
                          </td>
                        );
                      })}
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      ))}
    </div>
  );
};

export default ScheduleView;

import type { Schedule, DayOfWeek, Bartender, EarningsMap, ScheduledBartender } from '../types';

function getWeekData(schedule: Schedule, week: number) {
    return schedule.filter(s => s.week === week);
}

const DAY_ORDER: DayOfWeek[] = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun', 'Sun_Night'];
const FLOOR_ORDER = ['Rooftop', 'Hip Hop', "2010's", "2000's"];

function generateSummarySection(schedule: Schedule, bartenders: Bartender[], earningsMap: EarningsMap): string {
    const summary: Record<string, { shiftCount: number; totalEarnings: number }> = 
        bartenders.reduce((acc, b) => ({ ...acc, [b.name]: { shiftCount: 0, totalEarnings: 0 } }), {});

    schedule.forEach(entry => {
        const { floor, bar, day, bartenders: assigned } = entry;
        const earnings = earningsMap[floor]?.[bar]?.[day] || 0;

        assigned.forEach(b => {
            const name = b.name;
            if (!summary[name]) {
                 summary[name] = { shiftCount: 0, totalEarnings: 0 };
            }
            summary[name].shiftCount++;
            summary[name].totalEarnings += earnings;
        });
    });

    const summaryData = Object.entries(summary).map(([name, data]) => ({
        name,
        shiftCount: data.shiftCount,
        totalEarnings: data.totalEarnings,
        averageEarnings: data.shiftCount > 0 ? data.totalEarnings / data.shiftCount : 0
    })).sort((a, b) => a.name.localeCompare(b.name));

    let html = `<div class="section">
        <h2 class="section-title">📊 Summary</h2>
        <table class="summary-table">
            <thead>
                <tr>
                    <th>Bartender</th>
                    <th>Total Shifts</th>
                    <th>Total Earnings</th>
                    <th>Avg. / Shift</th>
                </tr>
            </thead>
            <tbody>`;

    summaryData.forEach(row => {
        html += `<tr>
            <td><strong>${row.name}</strong></td>
            <td style="text-align:center;">${row.shiftCount}</td>
            <td style="text-align:center;">$${row.totalEarnings.toFixed(2)}</td>
            <td style="text-align:center;">$${row.averageEarnings.toFixed(2)}</td>
        </tr>`;
    });

    html += `</tbody></table></div><hr style="border: 0; border-top: 2px solid #eee; margin: 30px 0;">`;
    return html;
}

function generateFloorDistributionSection(schedule: Schedule, bartenders: Bartender[]): string {
    const data: Record<string, Record<string, number>> = bartenders.reduce((acc, b) => {
        acc[b.name] = {};
        FLOOR_ORDER.forEach(floor => {
            acc[b.name][floor] = 0;
        });
        return acc;
    }, {} as Record<string, Record<string, number>>);

    schedule.forEach(entry => {
        const { floor, bartenders: assigned } = entry;
        assigned.forEach(b => {
            if (data[b.name] && data[b.name][floor] !== undefined) {
                data[b.name][floor]++;
            }
        });
    });

    const sortedNames = Object.keys(data).sort((a, b) => a.localeCompare(b));

    let html = `<div class="section">
        <h2 class="section-title">📍 Floor Distribution</h2>
        <table class="summary-table">
            <thead>
                <tr>
                    <th>Bartender</th>
                    ${FLOOR_ORDER.map(f => `<th>${f}</th>`).join('')}
                </tr>
            </thead>
            <tbody>`;

    sortedNames.forEach(name => {
        html += `<tr>
            <td><strong>${name}</strong></td>
            ${FLOOR_ORDER.map(f => `<td style="text-align:center;">${data[name][f]}</td>`).join('')}
        </tr>`;
    });

    html += `</tbody></table></div><hr style="border: 0; border-top: 2px solid #eee; margin: 30px 0;">`;
    return html;
}

function getFormattedDate(start: string, day: DayOfWeek, weekOffset: number) {
    const date = new Date(start + 'T00:00:00');
    const dayIndex = DAY_ORDER.indexOf(day);
    const offset = dayIndex === 7 ? 6 : dayIndex; 

    date.setDate(date.getDate() + offset + (weekOffset * 7));
    return `${day.replace('_', ' ')} ${date.getMonth() + 1}/${date.getDate()}`;
}

function generateWeeklySections(schedule: Schedule, startDate?: string): string {
    let html = `<div class="section">
        <h2 class="section-title">🗓️ Schedule</h2>`;

    for (let i = 1; i <= 4; i++) {
        const weekSchedule = getWeekData(schedule, i);
        if (weekSchedule.length === 0) continue;

        const scheduleGrid: Record<string, Record<string, ScheduledBartender[]>> = {};

        const daysInWeek = Array.from(new Set(weekSchedule.map(entry => entry.day)))
                                 .sort((a, b) => DAY_ORDER.indexOf(a) - DAY_ORDER.indexOf(b));

        weekSchedule.forEach(entry => {
            const key = `${entry.floor} / ${entry.bar}`;
            if (!scheduleGrid[key]) scheduleGrid[key] = {};
            scheduleGrid[key][entry.day] = entry.bartenders;
        });

        const uniqueKeys = Object.keys(scheduleGrid).sort((a, b) => {
            const [floorA, barA] = a.split(' / ');
            const [floorB, barB] = b.split(' / ');
            const indexA = FLOOR_ORDER.indexOf(floorA);
            const indexB = FLOOR_ORDER.indexOf(floorB);

            if (indexA !== indexB) {
                if (indexA === -1) return 1;
                if (indexB === -1) return -1;
                return indexA - indexB;
            }
            return barA.localeCompare(barB);
        });

        let title = `Week ${i}`;
        if (startDate) {
             const weekStart = new Date(startDate + 'T00:00:00');
             weekStart.setDate(weekStart.getDate() + (i - 1) * 7);
             title = `Week ${i} (Starting ${weekStart.toLocaleDateString()})`;
        }

        html += `<div class="week-table">
            <h3 class="week-title">${title}</h3>
            <table>
                <thead>
                    <tr>
                        <th>Shift (Floor / Bar)</th>
                        ${daysInWeek.map(d => {
                            const label = startDate ? getFormattedDate(startDate, d, i - 1) : d.replace('_', ' ');
                            return `<th>${label}</th>`;
                        }).join('')}
                    </tr>
                </thead>
                <tbody>`;

        uniqueKeys.forEach(key => {
            const [floor, bar] = key.split(' / ');
            const floorClass = `floor-${floor.toLowerCase().replace(/'s/g, '').replace(/\s+/g, '-')}`;
            html += `<tr class="${floorClass}">
                <td><strong>${floor}</strong><br><span class="bar-name">${bar}</span></td>`;
            daysInWeek.forEach(day => {
                const bartenders = scheduleGrid[key][day] || [];
                const bartenderStrings = bartenders.map(b => b.role ? `${b.name} (${b.role})` : b.name);
                html += `<td contenteditable="true" class="editable-cell">${bartenderStrings.join('<br>')}</td>`;
            });
            html += `</tr>`;
        });

        html += `</tbody></table></div>`;
    }

    html += `</div>`;
    return html;
}

