  `;

  const blob = new Blob([htmlContent], { type: 'text/html' });
  const link = document.createElement('a');
  link.href = URL.createObjectURL(blob);
  link.download = `schedule-report-${title.replace(/[\s/]+/g, '-')}.html`;
