const App: React.FC = () => {
  // --- State Initialization with Persistence ---
  const [bartenders, setBartenders] = useState<Bartender[]>(() => {
    const saved = window.localStorage.getItem('bartenders');
    return saved ? JSON.parse(saved) : initialBartenders;
  });

  const [fixedAssignments, setFixedAssignments] = useState<FixedAssignment[]>(() => {
    const saved = window.localStorage.getItem('fixedAssignments');
    return saved ? JSON.parse(saved) : initialFixedAssignments;
  });

  const [timeOffRequests, setTimeOffRequests] = useState<TimeOffRequest[]>(() => {
    const saved = window.localStorage.getItem('timeOffRequests');
    return saved ? JSON.parse(saved) : [];
  });

  const [targetShifts, setTargetShifts] = useState<TargetShifts>(() => {
    const saved = window.localStorage.getItem('targetShifts');
    return saved ? JSON.parse(saved) : {};
  });

  const [closedShifts, setClosedShifts] = useState<ClosedShift[]>(() => {
    const saved = window.localStorage.getItem('closedShifts');
    return saved ? JSON.parse(saved) : [];
  });

  const [generationMode, setGenerationMode] = useState<'monthly' | 'weekly' | 'daily'>('monthly');
  const [weeksToGenerate, setWeeksToGenerate] = useState<number>(5);
  const [startDate, setStartDate] = useState<string>(() => {
    const d = new Date();
    d.setDate(d.getDate() + (1 + 7 - d.getDay()) % 7);
    return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
  });

  const [dailyOverrides, setDailyOverrides] = useState<DailyOverride[]>([]);
  const [schedule, setSchedule] = useState<Schedule | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [statusMsg, setStatusMsg] = useState<string | null>(null);

  useEffect(() => {
    if (generationMode === 'monthly') setWeeksToGenerate(5);
    else if (generationMode === 'weekly') setWeeksToGenerate(1);
  }, [generationMode]);

  useEffect(() => window.localStorage.setItem('bartenders', JSON.stringify(bartenders)), [bartenders]);
  useEffect(() => window.localStorage.setItem('fixedAssignments', JSON.stringify(fixedAssignments)), [fixedAssignments]);
  useEffect(() => window.localStorage.setItem('timeOffRequests', JSON.stringify(timeOffRequests)), [timeOffRequests]);
  useEffect(() => window.localStorage.setItem('targetShifts', JSON.stringify(targetShifts)), [targetShifts]);
  useEffect(() => window.localStorage.setItem('closedShifts', JSON.stringify(closedShifts)), [closedShifts]);

  const getMonday = (d: Date) => {
    const day = d.getDay();
    const diff = d.getDate() - day + (day === 0 ? -6 : 1);
    const monday = new Date(d);
    monday.setDate(diff);
    return monday;
  }

  const getSpecificDay = useCallback(() => {
    if (generationMode !== 'daily') return undefined;
    const d = new Date(startDate + 'T00:00:00');
    const dayMap: DayOfWeek[] = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
    return dayMap[d.getDay()];
  }, [startDate, generationMode]);

  const handlePreviewFixed = useCallback(() => {
    setIsLoading(true);
    setStatusMsg('Preparing fixed assignment preview...');
    setTimeout(() => {
      try {
        const generated = generateFixedOnlySchedule(
            SHIFTS_TEMPLATE,
            fixedAssignments,
            closedShifts,
            weeksToGenerate,
            getSpecificDay(),
            generationMode === 'daily' ? dailyOverrides : []
        );
        setSchedule(generated);
      } catch (err) {
        setError('Error generating preview.');
      } finally {
        setIsLoading(false);
        setStatusMsg(null);
      }
    }, 50);
  }, [fixedAssignments, closedShifts, generationMode, weeksToGenerate, dailyOverrides, getSpecificDay]);

  const handleGenerateSchedule = useCallback(() => {
    setIsLoading(true);
    setStatusMsg('AI is calculating optimal distribution...');
    setError(null);
    setTimeout(() => {
      try {
        const effectiveBaseDate = getEffectiveMondayDate() || startDate;
        const generatedSchedule = generateSchedule(
            bartenders, 
            SHIFTS_TEMPLATE, 
            fixedAssignments, 
            targetShifts, 
            timeOffRequests, 
            closedShifts,
            weeksToGenerate,
            getSpecificDay(),
            generationMode === 'daily' ? dailyOverrides : [],
            effectiveBaseDate
        );
        setSchedule(generatedSchedule);
      } catch (err) {
        setError(err instanceof Error ? err.message : 'An error occurred.');
      } finally {
        setIsLoading(false);
        setStatusMsg(null);
      }
    }, 50);
  }, [bartenders, fixedAssignments, targetShifts, timeOffRequests, closedShifts, generationMode, weeksToGenerate, dailyOverrides, getSpecificDay, startDate]);

  const handleAssignBartender = useCallback((
    week: number, day: DayOfWeek, floor: string, bar: string, bartenderName: string | null
  ) => {
    if (!schedule) return;

    // Normalize strings for safety
    const nFloor = floor.trim();
    const nBar = bar.trim();

    // 1. Update Fixed Assignments State
    setFixedAssignments(prev => {
      // If name is null, we clear the whole shift cell
      if (!bartenderName) {
        return prev.filter(fa => 
          !(parseInt(fa.week.split('_')[1]) === week && 
            fa.day === day && 
            fa.floor.trim() === nFloor && 
            fa.bar.trim() === nBar)
        );
      }

      // Check if this specific bartender is already manually assigned here
      const isAlreadyAssigned = prev.some(fa => 
        fa.name === bartenderName && 
        parseInt(fa.week.split('_')[1]) === week && 
        fa.day === day && 
        fa.floor.trim() === nFloor && 
        fa.bar.trim() === nBar
      );

      // Toggle behavior: If they are already there, remove them. Otherwise, add them.
      if (isAlreadyAssigned) {
        return prev.filter(fa => 
          !(fa.name === bartenderName && 
            parseInt(fa.week.split('_')[1]) === week && 
            fa.day === day && 
            fa.floor.trim() === nFloor && 
            fa.bar.trim() === nBar)
        );
      }

      const newRule: FixedAssignment = {
        name: bartenderName,
        week: `Week_${week}` as any,
        day: day,
        floor: nFloor,
        bar: nBar
      };

      return [...prev, newRule];
    });

    // 2. Immediate UI Update
    setSchedule(prev => {
      if (!prev) return null;
      return prev.map(entry => {
        if (entry.week === week && entry.day === day && entry.floor.trim() === nFloor && entry.bar.trim() === nBar) {
          if (!bartenderName) return { ...entry, bartenders: [] };

          const isAlreadyInScheduleCell = entry.bartenders.some(b => b.name === bartenderName);
          if (isAlreadyInScheduleCell) {
             return { ...entry, bartenders: entry.bartenders.filter(b => b.name !== bartenderName) };
          }
          return { ...entry, bartenders: [...entry.bartenders, { name: bartenderName, role: 'Fixed' }] };
        }
        return entry;
      });
    });
  }, [schedule]);

  const handleMoveAssignment = useCallback((
    from: { week: number, day: DayOfWeek, floor: string, bar: string },
    to: { week: number, day: DayOfWeek, floor: string, bar: string },
    bartenderName: string
  ) => {
    if (!schedule) return;

    // 1. Update Fixed Assignments
    setFixedAssignments(prev => {
      const filtered = prev.filter(fa => 
        !(fa.name === bartenderName && 
          parseInt(fa.week.split('_')[1]) === from.week && 
          fa.day === from.day && 
          fa.floor.trim() === from.floor.trim() && 
          fa.bar.trim() === from.bar.trim())
      );

      const newRule: FixedAssignment = {
        name: bartenderName,
        week: `Week_${to.week}` as any,
        day: to.day,
        floor: to.floor.trim(),
        bar: to.bar.trim()
      };

      return [...filtered, newRule];
    });

    // 2. Immediate UI Update
    setSchedule(prev => {
      if (!prev) return null;
      return prev.map(entry => {
        // Remove from original cell
        if (entry.week === from.week && entry.day === from.day && entry.floor.trim() === from.floor.trim() && entry.bar.trim() === from.bar.trim()) {
          return { ...entry, bartenders: entry.bartenders.filter(b => b.name !== bartenderName) };
        }
        // Add to destination cell
        if (entry.week === to.week && entry.day === to.day && entry.floor.trim() === to.floor.trim() && entry.bar.trim() === to.bar.trim()) {
          if (entry.bartenders.some(b => b.name === bartenderName)) return entry;
          return { ...entry, bartenders: [...entry.bartenders, { name: bartenderName, role: 'Fixed' }] };
        }
        return entry;
      });
    });
  }, [schedule]);

  const scheduleTitle = useCallback(() => {
    if (!startDate) return 'Schedule';
    const dateObj = new Date(startDate + 'T00:00:00');
    if (generationMode === 'daily') return dateObj.toLocaleDateString(undefined, { weekday: 'long', month: 'short', day: 'numeric' });
    const startMonday = getMonday(dateObj);
    if (generationMode === 'weekly') return `Week of ${startMonday.toLocaleDateString()}`;
    const endDate = new Date(startMonday);
    endDate.setDate(endDate.getDate() + (weeksToGenerate * 7) - 1); 
    return `${startMonday.toLocaleDateString()} - ${endDate.toLocaleDateString()}`;
  }, [startDate, generationMode, weeksToGenerate])();

  const getEffectiveMondayDate = () => {
    if (!startDate) return undefined;
    const d = new Date(startDate + 'T00:00:00');
    const monday = getMonday(d);
    return `${monday.getFullYear()}-${String(monday.getMonth() + 1).padStart(2, '0')}-${String(monday.getDate()).padStart(2, '0')}`;
  };

  const effectiveStartDate = getEffectiveMondayDate();

  return (
    <div className="min-h-screen bg-slate-900 text-slate-200 font-sans p-4 sm:p-6 lg:p-8">
      <div className="max-w-screen-2xl mx-auto">
        <header className="mb-8">
          <h1 className="text-4xl sm:text-5xl font-bold text-white tracking-tight">
            AI Bartender Schedule Generator
          </h1>
          <p className="mt-2 text-lg text-slate-400">Smart logic for automated club scheduling.</p>
        </header>

        <main className="grid grid-cols-1 xl:grid-cols-4 xl:items-start gap-8">
          <aside className="xl:col-span-1 space-y-8 p-6 bg-slate-800/50 rounded-2xl border border-slate-700 shadow-lg xl:sticky xl:top-8 overflow-y-auto max-h-[calc(100vh-4rem)] custom-scrollbar">
            <div className="space-y-4 border-b border-slate-700 pb-6">
                <h3 className="text-base font-semibold text-slate-200">Schedule Mode</h3>
                <div className="flex bg-slate-900 rounded-lg p-1 border border-slate-600">
                    {['monthly', 'weekly', 'daily'].map((mode) => (
                      <button
                        key={mode}
                        onClick={() => setGenerationMode(mode as any)}
                        className={`flex-1 py-2 text-xs font-medium rounded-md transition-colors ${generationMode === mode ? 'bg-indigo-600 text-white shadow-sm' : 'text-slate-400 hover:text-slate-200'}`}
                      >
                        {mode.charAt(0).toUpperCase() + mode.slice(1)}
                      </button>
                    ))}
                </div>

                {generationMode !== 'daily' && (
                  <div>
                    <label className="block text-xs text-slate-400 mb-1">Number of Weeks</label>
                    <select 
                      value={weeksToGenerate}
                      onChange={(e) => setWeeksToGenerate(parseInt(e.target.value))}
                      className="w-full bg-slate-900/70 border border-slate-600 rounded-md py-2 px-3 text-sm text-slate-200"
                    >
                      {[1,2,3,4,5].map(n => <option key={n} value={n}>{n} Week{n > 1 ? 's' : ''}</option>)}
                    </select>
                  </div>
                )}

                <div>
                    <label className="block text-xs text-slate-400 mb-1">Start Date</label>
                    <div className="relative">
                        <CalendarIcon className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-slate-400 pointer-events-none"/>
                        <input type="date" value={startDate} onChange={(e) => setStartDate(e.target.value)} className="w-full bg-slate-900/70 border border-slate-600 rounded-md py-2 pl-9 text-sm text-slate-200 focus:ring-1 focus:ring-indigo-500" />
                    </div>
                </div>
            </div>

            {generationMode === 'daily' && getSpecificDay() && (
                 <DailyOverrideManager dailyOverrides={dailyOverrides} setDailyOverrides={setDailyOverrides} bartenders={bartenders} shifts={SHIFTS_TEMPLATE} specificDay={getSpecificDay()!} />
            )}

            <BartenderManager bartenders={bartenders} setBartenders={setBartenders} />
            <WeeklyAvailabilityManager bartenders={bartenders} setBartenders={setBartenders} />
            <FixedShiftManager fixedAssignments={fixedAssignments} setFixedAssignments={setFixedAssignments} bartenders={bartenders} shifts={SHIFTS_TEMPLATE} />
            <TimeOffRequestManager timeOffRequests={timeOffRequests} setTimeOffRequests={setTimeOffRequests} bartenders={bartenders} />
            <TargetShiftsManager targetShifts={targetShifts} setTargetShifts={setTargetShifts} />
            <EventShiftManager closedShifts={closedShifts} setClosedShifts={setClosedShifts} shifts={SHIFTS_TEMPLATE} />

            <div className="pt-4 border-t border-slate-700 space-y-3">
              <button
                onClick={handlePreviewFixed}
                disabled={isLoading}
                className="w-full flex items-center justify-center gap-2 bg-slate-700 text-slate-100 font-semibold py-2.5 px-4 rounded-lg hover:bg-slate-600 transition-colors"
              >
                <EyeIcon className="h-5 w-5" />
                Preview Fixed Only
              </button>
              <button
                onClick={handleGenerateSchedule}
                disabled={isLoading}
                className="w-full flex items-center justify-center gap-2 bg-indigo-600 text-white font-bold py-3 px-4 rounded-lg hover:bg-indigo-500 disabled:bg-slate-600 transition-all shadow-[0_4px_12px_rgba(79,70,229,0.3)]"
              >
                {isLoading ? <span className="animate-pulse">{statusMsg || 'Working...'}</span> : <><CalendarIcon className="h-5 w-5" /> Generate Full Schedule</>}
              </button>
            </div>
          </aside>

          <section className="xl:col-span-3 p-6 bg-slate-800/50 rounded-2xl border border-slate-700 shadow-lg min-h-[80vh]">
            <div className="flex flex-col sm:flex-row justify-between sm:items-center mb-6 gap-4">
              <h2 className="text-2xl font-bold text-white uppercase tracking-wide">{scheduleTitle}</h2>
              {schedule && schedule.length > 0 && (
                <button onClick={() => exportScheduleToHtml(schedule, scheduleTitle, bartenders, EARNINGS_MAP, effectiveStartDate)} className="flex items-center gap-2 bg-slate-700 text-slate-200 py-2 px-4 rounded-lg hover:bg-slate-600 transition-colors">
                  <DownloadIcon className="h-5 w-5" /> Export HTML
                </button>
              )}
            </div>

            {error && <div className="bg-red-900/50 border border-red-700 text-red-300 px-4 py-3 rounded-lg mb-4">{error}</div>}

            <div className="space-y-8">
              {schedule && schedule.length > 0 ? (
                <>
                  <SummaryView schedule={schedule} bartenders={bartenders} earningsMap={EARNINGS_MAP} />
                  <FloorDistributionView schedule={schedule} bartenders={bartenders} />
                  <ScheduleView 
                    schedule={schedule} 
                    startDate={effectiveStartDate} 
                    onMoveAssignment={handleMoveAssignment}
                    onAssignBartender={handleAssignBartender}
                    bartenders={bartenders}
                  />
                </>
              ) : (
                 !isLoading && (
                  <div className="flex flex-col items-center justify-center min-h-[400px] text-center text-slate-500 border-2 border-dashed border-slate-700 rounded-xl">
                      <CalendarIcon className="h-12 w-12 mb-4 opacity-20"/>
                      <p className="text-lg font-medium">Ready to build your schedule.</p>
                      <p className="text-sm mt-1 max-w-sm">Use "Preview Fixed Only" to see your manual setup, or "Generate Full Schedule" to let the AI fill the blanks.</p>
                  </div>
                 )
              )}
              {isLoading && (
                  <div className="flex flex-col items-center justify-center min-h-[400px] text-center text-slate-500">
                    <div className="w-12 h-12 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mb-4"></div>
                    <p className="text-lg font-medium">{statusMsg || 'Generating schedule...'}</p>
                  </div>
              )}
            </div>
          </section>
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useMemo, useState, useEffect, useRef } from 'react';
import type { Schedule, DayOfWeek, ScheduledBartender, Bartender } from '../types';
import { PlusIcon } from './icons/PlusIcon';
import { TrashIcon } from './icons/TrashIcon';

interface ScheduleViewProps {
  schedule: Schedule;
  startDate?: string;
  bartenders?: Bartender[];
  onMoveAssignment?: (
    from: { week: number, day: DayOfWeek, floor: string, bar: string },
    to: { week: number, day: DayOfWeek, floor: string, bar: string },
    bartenderName: string
  ) => void;
  onAssignBartender?: (
    week: number, day: DayOfWeek, floor: string, bar: string, bartenderName: string | null
  ) => void;
}

const DAY_ORDER: DayOfWeek[] = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun', 'Sun_Night'];
const FLOOR_ORDER = ['Rooftop', 'Hip Hop', "2010's", "2000's"];

const ScheduleView: React.FC<ScheduleViewProps> = ({ schedule, startDate, onMoveAssignment, onAssignBartender, bartenders = [] }) => {
  const [dragOverCell, setDragOverCell] = useState<string | null>(null);
  const [editingCell, setEditingCell] = useState<string | null>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Close dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setEditingCell(null);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Group data and calculate weekly counts for badges
  const groupedData = useMemo(() => {
    if (!schedule.length) return [];
    const maxWeek = Math.max(...schedule.map(s => s.week));
    const weeks = Array.from({ length: maxWeek }, (_, i) => i + 1);

    return weeks.map(week => {
      const weekSchedule = schedule.filter(s => s.week === week);
      if (weekSchedule.length === 0) return null;

      const grid: Record<string, Record<string, ScheduledBartender[]>> = {};
      const days = [...new Set<DayOfWeek>(weekSchedule.map(entry => entry.day))].sort((a, b) => DAY_ORDER.indexOf(a) - DAY_ORDER.indexOf(b));

      // Calculate shift counts for this specific week
      const weeklyCounts: Record<string, number> = {};
      weekSchedule.forEach(entry => {
        entry.bartenders.forEach(b => {
            weeklyCounts[b.name] = (weeklyCounts[b.name] || 0) + 1;
        });

        const key = `${entry.floor.trim()} / ${entry.bar.trim()}`;
        if (!grid[key]) grid[key] = {};
        grid[key][entry.day] = entry.bartenders;
      });

      const uniqueKeys = Object.keys(grid).sort((a, b) => {
          const [floorA, barA] = a.split(' / ');
          const [floorB, barB] = b.split(' / ');
          const indexA = FLOOR_ORDER.indexOf(floorA);
          const indexB = FLOOR_ORDER.indexOf(floorB);
          if (indexA !== indexB) return (indexA === -1 ? 1 : indexB === -1 ? -1 : indexA - indexB);
          return barA.localeCompare(barB);
      });

      return { week, grid, days, uniqueKeys, weeklyCounts };
    }).filter(w => w !== null);
  }, [schedule]);

  const getFormattedDate = (start: string, day: DayOfWeek, weekIndex: number) => {
    const date = new Date(start + 'T00:00:00');
    const dayIndex = DAY_ORDER.indexOf(day);
    const offset = dayIndex === 7 ? 6 : dayIndex; 
    date.setDate(date.getDate() + offset + ((weekIndex - 1) * 7));
    return `${day.replace('_', ' ')} ${date.getMonth() + 1}/${date.getDate()}`;
  }

  // Drag and Drop handlers
  const handleDragStart = (e: React.DragEvent, bartenderName: string, week: number, day: string, floor: string, bar: string) => {
    const dragData = { name: bartenderName, from: { week, day, floor, bar } };
    e.dataTransfer.setData('application/json', JSON.stringify(dragData));
    e.dataTransfer.effectAllowed = 'move';
  };

  const handleDragOver = (e: React.DragEvent, cellKey: string) => {
    e.preventDefault();
    setDragOverCell(cellKey);
  };

  const handleDrop = (e: React.DragEvent, week: number, day: DayOfWeek, floor: string, bar: string) => {
    e.preventDefault();
    setDragOverCell(null);
    try {
        const data = JSON.parse(e.dataTransfer.getData('application/json'));
        if (onMoveAssignment && data.from && data.name) {
            onMoveAssignment(data.from, { week, day, floor, bar }, data.name);
        }
    } catch (err) {
        console.error("Failed to parse drag data", err);
    }
  };

  const toggleEditing = (cellKey: string) => {
    setEditingCell(prev => prev === cellKey ? null : cellKey);
  }

  const handleQuickAssign = (week: number, day: DayOfWeek, floor: string, bar: string, name: string | null) => {
    if (onAssignBartender) {
      onAssignBartender(week, day, floor, bar, name);
    }
    // We don't close the menu automatically if adding multiple, 
    // but the user's logic might prefer closing it. Let's close for simplicity.
    setEditingCell(null);
  }

  return (
    <div className="space-y-8 select-none">
      {groupedData.map(({ week, grid, days, uniqueKeys, weeklyCounts }) => (
        <div key={week} className="animate-fadeIn">
          <div className="flex items-center gap-3 mb-4">
             <h3 className="text-xl font-bold text-white bg-indigo-600/20 px-4 py-1 rounded-full border border-indigo-500/30">Week {week}</h3>
             <div className="h-[1px] flex-1 bg-slate-700/50"></div>
          </div>
          <div className="overflow-x-auto rounded-xl border border-slate-700/50 bg-slate-800/30 shadow-inner">
            <table className="w-full min-w-[900px] text-sm text-left border-separate border-spacing-0">
              <thead className="text-xs text-slate-400 uppercase bg-slate-900/50 sticky top-0 z-20">
                <tr>
                  <th className="px-6 py-4 font-bold border-r border-b border-slate-700/50 bg-slate-900/50">Shift</th>
                  {days.map(day => (
                    <th key={day} className="px-6 py-4 text-center border-b border-slate-700/50 bg-slate-900/50">
                      {startDate ? getFormattedDate(startDate, day as DayOfWeek, week) : day.replace('_', ' ')}
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-700/50">
                {uniqueKeys.map((key, rowIndex) => {
                  const [floor, bar] = key.split(' / ');
                  return (
                    <tr key={key} className="hover:bg-slate-700/10 transition-colors group">
                      <td className="px-6 py-4 border-r border-slate-700/50 font-medium sticky left-0 z-10 bg-slate-800/95 group-hover:bg-slate-700/20 transition-colors">
                        <div className="font-bold text-slate-200 group-hover:text-indigo-300 transition-colors">{floor}</div>
                        <div className="text-[10px] uppercase tracking-wider text-slate-500 font-medium">{bar}</div>
                      </td>
                      {days.map(day => {
                        const cellBartenders = grid[key][day] || [];
                        const cellKey = `${week}-${key}-${day}`;
                        const isOver = dragOverCell === cellKey;
                        const isEditing = editingCell === cellKey;

                        // Decide if dropdown should open upwards or downwards
                        const isLastRows = rowIndex > uniqueKeys.length - 4;

                        return (
                          <td 
                            key={day} 
                            className={`px-6 py-4 text-center align-top transition-all duration-200 cursor-pointer relative ${isOver ? 'bg-indigo-600/30 scale-[1.02] shadow-[inset_0_0_10px_rgba(79,70,229,0.3)]' : ''}`}
                            onDragOver={(e) => handleDragOver(e, cellKey)}
                            onDragLeave={() => setDragOverCell(null)}
                            onDrop={(e) => handleDrop(e, week, day as DayOfWeek, floor, bar)}
                            onClick={(e) => {
                                e.preventDefault();
                                toggleEditing(cellKey);
                            }}
                          >
                            <div className="absolute top-2 right-2 opacity-0 group-hover:opacity-40 transition-opacity">
                                <PlusIcon className="w-4 h-4 text-slate-400" />
                            </div>

                            {cellBartenders.length > 0 ? (
                              <div className="space-y-3 pointer-events-none">
                                {cellBartenders.map((b, idx) => (
                                  <div 
                                    key={idx} 
                                    draggable
                                    onDragStart={(e) => {
                                        e.stopPropagation(); // Allow dragging handles
                                        handleDragStart(e, b.name, week, day, floor, bar);
                                    }}
                                    className="flex flex-col items-center cursor-grab active:cursor-grabbing hover:scale-110 transition-transform duration-150 pointer-events-auto"
                                    onClick={(e) => e.stopPropagation()} 
                                  >
                                    <div className="flex items-center gap-1.5 relative group/name">
                                        <span className={`font-semibold text-sm ${b.role === 'Fixed' ? 'text-amber-400' : 'text-slate-200'}`}>
                                            {b.name}
                                        </span>
                                        <span 
                                            className="text-[10px] bg-slate-900/80 text-indigo-400 font-bold px-1.5 py-0 rounded-full border border-indigo-500/30 shadow-sm" 
                                            title={`Total shifts this week for ${b.name}`}
                                        >
                                            {weeklyCounts[b.name] || 0}
                                        </span>
                                    </div>
                                    {b.role && (
                                      <span className={`text-[9px] mt-1 uppercase font-bold px-1.5 py-0.5 rounded ${b.role === 'Fixed' ? 'bg-amber-900/40 text-amber-500 border border-amber-800/50' : 'bg-indigo-900/40 text-indigo-400 border border-indigo-800/50'}`}>
                                        {b.role}
                                      </span>
                                    )}
                                  </div>
                                ))}
                              </div>
                            ) : (
                              <div className="py-2 pointer-events-none">
                                <span className="text-[10px] font-bold text-slate-600 uppercase tracking-widest bg-slate-900/10 px-3 py-1.5 rounded-md border border-slate-700/20 block">Open</span>
                              </div>
                            )}

                            {/* Floating Dropdown for Quick Assignment */}
                            {isEditing && (
                              <div 
                                ref={dropdownRef}
                                className={`absolute z-[100] left-1/2 -translate-x-1/2 ${isLastRows ? 'bottom-full mb-2' : 'top-full mt-2'} w-52 bg-slate-800 border border-slate-600 rounded-lg shadow-[0_10px_40px_rgba(0,0,0,0.6)] overflow-hidden animate-fadeIn`}
                                onClick={(e) => e.stopPropagation()}
                              >
                                <div className="p-3 border-b border-slate-700 bg-slate-900/80 text-[10px] uppercase font-bold text-slate-400 tracking-wider flex justify-between items-center">
                                  <span>Manage Shift</span>
                                  <span className="text-slate-600 text-[8px]">{day} - {bar}</span>
                                </div>
                                <div className="max-h-72 overflow-y-auto custom-scrollbar">
                                  <button 
                                    onClick={() => handleQuickAssign(week, day as DayOfWeek, floor, bar, null)}
                                    className="w-full text-left px-4 py-3 text-xs text-red-400 hover:bg-red-900/20 flex items-center gap-2 transition-colors border-b border-slate-700"
                                  >
                                    <TrashIcon className="w-4 h-4" /> Clear All Assignments
                                  </button>
                                  <div className="bg-slate-900/20 py-1">
                                    {bartenders.map(b => {
                                      const isCurrentlyAssigned = cellBartenders.some(cb => cb.name === b.name);
                                      return (
                                        <button 
                                          key={b.name}
                                          onClick={() => handleQuickAssign(week, day as DayOfWeek, floor, bar, b.name)}
                                          className={`w-full text-left px-4 py-2.5 text-sm transition-colors flex justify-between items-center ${isCurrentlyAssigned ? 'bg-indigo-900/30 text-indigo-300' : 'text-slate-200 hover:bg-indigo-600'}`}
                                        >
                                          <div className="flex items-center gap-2">
                                              <span>{b.name}</span>
                                              {isCurrentlyAssigned && <div className="w-1.5 h-1.5 rounded-full bg-indigo-400 animate-pulse"></div>}
                                          </div>
                                          <span className="text-[10px] text-slate-500 font-mono">T{b.tier}</span>
                                        </button>
                                      );
                                    })}
                                  </div>
                                </div>
                              </div>
                            )}
                          </td>
                        );
                      })}
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      ))}
    </div>
  );
};

export default ScheduleView;

import type { Schedule, Bartender, Shift, FixedAssignment, TargetShifts, TimeOffRequest, DayOfWeek, ClosedShift, ScheduledBartender, DailyOverride } from '../types';

const DAY_ORDER: DayOfWeek[] = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun', 'Sun_Night'];

/**
 * Calculates a date string for a specific week and day relative to a start date.
 */
function getShiftDate(baseDateStr: string, week: number, day: DayOfWeek): string {
  if (!baseDateStr) return new Date().toISOString().split('T')[0];
  const date = new Date(baseDateStr + 'T00:00:00');
  const dayIndex = DAY_ORDER.indexOf(day);
  const offset = dayIndex === 7 ? 6 : dayIndex; // Sun and Sun_Night use same day offset
  date.setDate(date.getDate() + offset + ((week - 1) * 7));
  return date.toISOString().split('T')[0];
}

/**
 * Checks if a bartender is available for a specific shift, considering all constraints.
 */
function isBartenderAvailable(
  bartender: Bartender,
  shiftDate: string,
  day: DayOfWeek,
  timeOffMap: Set<string>,
  shiftsThisDay: Set<string> // Set of bartenders already scheduled on this day
): boolean {
  if (bartender.unavailableDays.includes(day)) return false;
  if (timeOffMap.has(`${bartender.name}-${shiftDate}`)) return false;
  if (shiftsThisDay.has(bartender.name)) return false;
  return true;
}

/**
 * Creates a fast-lookup Set for all time off requests based on calendar dates.
 */
function createTimeOffMap(timeOffRequests: TimeOffRequest[]): Set<string> {
  const timeOffMap = new Set<string>();
  timeOffRequests.forEach(req => {
    const start = new Date(req.startDate + 'T00:00:00');
    const end = new Date(req.endDate + 'T00:00:00');

    let current = new Date(start);
    while (current <= end) {
      const dateStr = current.toISOString().split('T')[0];
      timeOffMap.add(`${req.name}-${dateStr}`);
      current.setDate(current.getDate() + 1);
    }
  });
  return timeOffMap;
}

/**
 * Generates a schedule structure with ONLY manual assignments filled.
 */
export function generateFixedOnlySchedule(
    shiftsTemplate: Shift[],
    fixedAssignments: FixedAssignment[],
    closedShifts: ClosedShift[],
    weeksToGenerate: number = 5,
    specificDay?: DayOfWeek,
    dailyOverrides: DailyOverride[] = []
): Schedule {
  const schedule: Schedule = [];
  const closedShiftsSet = new Set(closedShifts.map(cs => `${cs.week}-${cs.day}-${(cs.floor || '').trim()}-${(cs.bar || '').trim()}`));

  // 1. Setup blank structure from template
  for (let week = 1; week <= weeksToGenerate; week++) {
    const weekString = `Week_${week}` as const;
    shiftsTemplate.forEach(shift => {
      if (specificDay && shift.day !== specificDay && !(specificDay === 'Sun' && shift.day === 'Sun_Night')) return;

      const floor = (shift.floor || '').trim();
      const bar = (shift.bar || '').trim();
      const shiftIdentifier = `${weekString}-${shift.day}-${floor}-${bar}`;
      if (!closedShiftsSet.has(shiftIdentifier)) {
          schedule.push({
            week,
            day: shift.day,
            floor: floor,
            bar: bar,
            bartenders: [],
          });
      }
    });
  }

  // 2. Apply Overrides (Daily)
  if (specificDay) {
    dailyOverrides.forEach(d => {
      const shift = schedule.find(s => 
        s.week === 1 && 
        s.day === d.day && 
        (s.floor || '').trim() === (d.floor || '').trim() && 
        (s.bar || '').trim() === (d.bar || '').trim()
      );
      if (shift && !shift.bartenders.some(b => b.name === d.name)) {
        shift.bartenders.push({ name: d.name, role: 'Fixed' });
      }
    });
  }

  // 3. Apply Fixed Assignments
  fixedAssignments.forEach(fa => {
    const weekNum = parseInt(fa.week.split('_')[1]);
    if (weekNum > weeksToGenerate) return;
    if (specificDay && fa.day !== specificDay && !(specificDay === 'Sun' && fa.day === 'Sun_Night')) return;

    const faFloor = (fa.floor || '').trim();
    const faBar = (fa.bar || '').trim();

    let shift = schedule.find(s => 
      s.week === weekNum && 
      s.day === fa.day && 
      (s.floor || '').trim() === faFloor && 
      (s.bar || '').trim() === faBar
    );

    // If the manual assignment is for a shift NOT in the template, create it
    if (!shift) {
        shift = {
            week: weekNum,
            day: fa.day,
            floor: faFloor,
            bar: faBar,
            bartenders: []
        };
        schedule.push(shift);
    }

    if (!shift.bartenders.some(b => b.name === fa.name)) {
      shift.bartenders.push({ name: fa.name, role: 'Fixed' });
    }
  });

  return schedule.sort((a,b) => {
    if (a.week !== b.week) return a.week - b.week;
    const dayIndexA = DAY_ORDER.indexOf(a.day);
    const dayIndexB = DAY_ORDER.indexOf(b.day);
    if(dayIndexA !== dayIndexB) return dayIndexA - dayIndexB;
    return (a.floor || '').localeCompare(b.floor || '');
  });
}

/**
 * The main function to generate a schedule using a deterministic algorithm.
 */
export function generateSchedule(
    bartenders: Bartender[], 
    shiftsTemplate: Shift[],
    fixedAssignments: FixedAssignment[],
    targetShifts: TargetShifts,
    timeOffRequests: TimeOffRequest[],
    closedShifts: ClosedShift[],
    weeksToGenerate: number = 5,
    specificDay?: DayOfWeek,
    dailyOverrides: DailyOverride[] = [],
    calendarStartDate: string = '' // YYYY-MM-DD
): Schedule {
  // Use the robust structure builder
  const schedule = generateFixedOnlySchedule(shiftsTemplate, fixedAssignments, closedShifts, weeksToGenerate, specificDay, dailyOverrides);

  const shiftCounts: Record<string, number> = bartenders.reduce((acc, b) => ({ ...acc, [b.name]: 0 }), {});
  // Pre-fill shift counts from fixed assignments
  schedule.forEach(s => s.bartenders.forEach(b => { if(shiftCounts[b.name] !== undefined) shiftCounts[b.name]++; }));

  const timeOffMap = createTimeOffMap(timeOffRequests);
  const saturday2000sWorkers = new Set<string>();

  // Identify Sat 2000s workers from fixed assignments
  schedule.filter(s => s.day === 'Sat' && (s.floor || '').trim() === "2000's").forEach(s => s.bartenders.forEach(b => saturday2000sWorkers.add(b.name)));

  // Fill remaining slots
  for (let week = 1; week <= weeksToGenerate; week++) {
    const shiftsForWeek = schedule.filter(s => s.week === week).sort((a,b) => DAY_ORDER.indexOf(a.day) - DAY_ORDER.indexOf(b.day));

    shiftsForWeek.forEach(shift => {
      const day = shift.day;
      const shiftDate = getShiftDate(calendarStartDate, week, day);

      const scheduledThisDay = new Set<string>();
      schedule.filter(s => s.week === week && s.day === day).forEach(s => s.bartenders.forEach(b => scheduledThisDay.add(b.name)));

      const shiftInfo = shiftsTemplate.find(t => t.day === shift.day && (t.floor || '').trim() === (shift.floor || '').trim() && (t.bar || '').trim() === (shift.bar || '').trim());
      const bartendersNeeded = shiftInfo ? shiftInfo.bartendersNeeded : 1;
      const neededCount = bartendersNeeded - shift.bartenders.length;
      if (neededCount <= 0) return;

      let availableCandidates = bartenders.filter(b => isBartenderAvailable(b, shiftDate, day, timeOffMap, scheduledThisDay));
      if (day === 'Sat' && (shift.floor || '').trim() === "2000's") availableCandidates = availableCandidates.filter(c => !saturday2000sWorkers.has(c.name));

      availableCandidates.sort((a, b) => {
          const needA = (targetShifts[a.name] || 0) - (shiftCounts[a.name] || 0);
          const needB = (targetShifts[b.name] || 0) - (shiftCounts[b.name] || 0);
          if (needA !== needB) return needB - needA;
          return Math.random() - 0.5;
      });

      const genderConstraint = shiftInfo?.gender;
      const toAssign: Bartender[] = [];

      if (genderConstraint === 'MF') {
          const maleCandidates = availableCandidates.filter(c => c.gender === 'Male');
          const femaleCandidates = availableCandidates.filter(c => c.gender === 'Female');
          if (maleCandidates.length > 0) toAssign.push(maleCandidates[0]);
          if (femaleCandidates.length > 0) toAssign.push(femaleCandidates[0]);
          while(toAssign.length < neededCount) {
             const next = availableCandidates.find(c => !toAssign.includes(c));
             if (next) toAssign.push(next); else break;
          }
      } else {
          toAssign.push(...availableCandidates.slice(0, neededCount));
      }

      toAssign.forEach(bartender => {
          shift.bartenders.push({ name: bartender.name, role: null });
          shiftCounts[bartender.name]++;
          scheduledThisDay.add(bartender.name);
          if (day === 'Sat' && (shift.floor || '').trim() === "2000's") saturday2000sWorkers.add(bartender.name);
      });
    });
  }

  // Final role assignment
  schedule.forEach(shift => {
    if (shift.bartenders.length > 1) {
      const hasDefinedRole = shift.bartenders.some(b => b.role === 'Point' || b.role === 'Fixed');
      if (!hasDefinedRole) {
          shift.bartenders[0].role = 'Point';
      }
    }
  });

  return schedule.sort((a,b) => {
    if (a.week !== b.week) return a.week - b.week;
    const dayIndexA = DAY_ORDER.indexOf(a.day);
    const dayIndexB = DAY_ORDER.indexOf(b.day);
    if(dayIndexA !== dayIndexB) return dayIndexA - dayIndexB;
    return (a.floor || '').localeCompare(b.floor || '');
  });
}

import React, { useState, useCallback, useEffect } from 'react';
import type { Schedule, Bartender, FixedAssignment, TargetShifts, TimeOffRequest, ClosedShift, DayOfWeek, DailyOverride, ScheduleEntry } from './types';
import { BARTENDERS as initialBartenders, SHIFTS_TEMPLATE, FIXED_ASSIGNMENTS as initialFixedAssignments, EARNINGS_MAP } from './data';
import { generateSchedule, generateFixedOnlySchedule } from './services/schedulingAlgorithm';
import { exportScheduleToHtml } from './utils/scheduleExporter';
import ScheduleView from './components/ScheduleView';
import SummaryView from './components/SummaryView';
import BartenderManager from './components/BartenderManager';
import FixedShiftManager from './components/FixedShiftManager';
import WeeklyAvailabilityManager from './components/WeeklyAvailabilityManager';
import TimeOffRequestManager from './components/TimeOffRequestManager';
import TargetShiftsManager from './components/TargetShiftsManager';
import EventShiftManager from './components/EventShiftManager';
import DailyOverrideManager from './components/DailyOverrideManager';
import { DownloadIcon } from './components/icons/DownloadIcon';
import { CalendarIcon } from './components/icons/CalendarIcon';
import { EyeIcon } from './components/icons/EyeIcon';
import FloorDistributionView from './components/FloorDistributionView';

const App: React.FC = () => {
  // --- State Initialization with Persistence ---
  const [bartenders, setBartenders] = useState<Bartender[]>(() => {
    const saved = window.localStorage.getItem('bartenders');
    return saved ? JSON.parse(saved) : initialBartenders;
  });

  const [fixedAssignments, setFixedAssignments] = useState<FixedAssignment[]>(() => {
    const saved = window.localStorage.getItem('fixedAssignments');
    return saved ? JSON.parse(saved) : initialFixedAssignments;
  });

  const [timeOffRequests, setTimeOffRequests] = useState<TimeOffRequest[]>(() => {
    const saved = window.localStorage.getItem('timeOffRequests');
    return saved ? JSON.parse(saved) : [];
  });

  const [targetShifts, setTargetShifts] = useState<TargetShifts>(() => {
    const saved = window.localStorage.getItem('targetShifts');
    return saved ? JSON.parse(saved) : {};
  });

  const [closedShifts, setClosedShifts] = useState<ClosedShift[]>(() => {
    const saved = window.localStorage.getItem('closedShifts');
    return saved ? JSON.parse(saved) : [];
  });

  const [generationMode, setGenerationMode] = useState<'monthly' | 'weekly' | 'daily'>('monthly');
  const [weeksToGenerate, setWeeksToGenerate] = useState<number>(5);
  const [startDate, setStartDate] = useState<string>(() => {
    const d = new Date();
    d.setDate(d.getDate() + (1 + 7 - d.getDay()) % 7);
    return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
  });

  const [dailyOverrides, setDailyOverrides] = useState<DailyOverride[]>([]);
  const [schedule, setSchedule] = useState<Schedule | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [statusMsg, setStatusMsg] = useState<string | null>(null);

  useEffect(() => {
    if (generationMode === 'monthly') setWeeksToGenerate(5);
    else if (generationMode === 'weekly') setWeeksToGenerate(1);
  }, [generationMode]);

  useEffect(() => window.localStorage.setItem('bartenders', JSON.stringify(bartenders)), [bartenders]);
  useEffect(() => window.localStorage.setItem('fixedAssignments', JSON.stringify(fixedAssignments)), [fixedAssignments]);
  useEffect(() => window.localStorage.setItem('timeOffRequests', JSON.stringify(timeOffRequests)), [timeOffRequests]);
  useEffect(() => window.localStorage.setItem('targetShifts', JSON.stringify(targetShifts)), [targetShifts]);
  useEffect(() => window.localStorage.setItem('closedShifts', JSON.stringify(closedShifts)), [closedShifts]);

  const getMonday = (d: Date) => {
    const day = d.getDay();
    const diff = d.getDate() - day + (day === 0 ? -6 : 1);
    const monday = new Date(d);
    monday.setDate(diff);
    return monday;
  }

  const getSpecificDay = useCallback(() => {
    if (generationMode !== 'daily') return undefined;
    const d = new Date(startDate + 'T00:00:00');
    const dayMap: DayOfWeek[] = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
    return dayMap[d.getDay()];
  }, [startDate, generationMode]);

  const handlePreviewFixed = useCallback(() => {
    setIsLoading(true);
    setStatusMsg('Preparing fixed assignment preview...');
    setTimeout(() => {
      try {
        const generated = generateFixedOnlySchedule(
            SHIFTS_TEMPLATE,
            fixedAssignments,
            closedShifts,
            weeksToGenerate,
            getSpecificDay(),
            generationMode === 'daily' ? dailyOverrides : []
        );
        setSchedule(generated);
      } catch (err) {
        setError('Error generating preview.');
      } finally {
        setIsLoading(false);
        setStatusMsg(null);
      }
    }, 50);
  }, [fixedAssignments, closedShifts, generationMode, weeksToGenerate, dailyOverrides, getSpecificDay]);

  const handleGenerateSchedule = useCallback(() => {
    setIsLoading(true);
    setStatusMsg('AI is calculating optimal distribution...');
    setError(null);
    setTimeout(() => {
      try {
        const effectiveBaseDate = getEffectiveMondayDate() || startDate;
        const generatedSchedule = generateSchedule(
            bartenders, 
            SHIFTS_TEMPLATE, 
            fixedAssignments, 
            targetShifts, 
            timeOffRequests, 
            closedShifts,
            weeksToGenerate,
            getSpecificDay(),
            generationMode === 'daily' ? dailyOverrides : [],
            effectiveBaseDate
        );
        setSchedule(generatedSchedule);
      } catch (err) {
        setError(err instanceof Error ? err.message : 'An error occurred.');
      } finally {
        setIsLoading(false);
        setStatusMsg(null);
      }
    }, 50);
  }, [bartenders, fixedAssignments, targetShifts, timeOffRequests, closedShifts, generationMode, weeksToGenerate, dailyOverrides, getSpecificDay, startDate]);

  const handleAssignBartender = useCallback((
    week: number, day: DayOfWeek, floor: string, bar: string, bartenderName: string | null
  ) => {
    if (!schedule) return;

    // Normalize strings for safety
    const nFloor = (floor || '').trim();
    const nBar = (bar || '').trim();

    // 1. Update Fixed Assignments State
    setFixedAssignments(prev => {
      if (!bartenderName) {
        return prev.filter(fa => 
          !(parseInt(fa.week.split('_')[1]) === week && 
            fa.day === day && 
            (fa.floor || '').trim() === nFloor && 
            (fa.bar || '').trim() === nBar)
        );
      }

      const isAlreadyAssigned = prev.some(fa => 
        fa.name === bartenderName && 
        parseInt(fa.week.split('_')[1]) === week && 
        fa.day === day && 
        (fa.floor || '').trim() === nFloor && 
        (fa.bar || '').trim() === nBar
      );

      if (isAlreadyAssigned) {
        return prev.filter(fa => 
          !(fa.name === bartenderName && 
            parseInt(fa.week.split('_')[1]) === week && 
            fa.day === day && 
            (fa.floor || '').trim() === nFloor && 
            (fa.bar || '').trim() === nBar)
        );
      }

      const newRule: FixedAssignment = {
        name: bartenderName,
        week: `Week_${week}` as any,
        day: day,
        floor: nFloor,
        bar: nBar
      };
      return [...prev, newRule];
    });

    // 2. Immediate UI Update
    setSchedule(prev => {
      if (!prev) return null;
      let found = false;
      const next = prev.map(entry => {
        if (entry.week === week && entry.day === day && (entry.floor || '').trim() === nFloor && (entry.bar || '').trim() === nBar) {
          found = true;
          if (!bartenderName) return { ...entry, bartenders: [] };
          const isAlreadyInScheduleCell = entry.bartenders.some(b => b.name === bartenderName);
          if (isAlreadyInScheduleCell) {
             return { ...entry, bartenders: entry.bartenders.filter(b => b.name !== bartenderName) };
          }
          return { ...entry, bartenders: [...entry.bartenders, { name: bartenderName, role: 'Fixed' }] };
        }
        return entry;
      });

      // BUG FIX: If no entry existed for this cell, create it now!
      if (!found && bartenderName) {
        const newEntry: ScheduleEntry = {
            week,
            day,
            floor: nFloor,
            bar: nBar,
            bartenders: [{ name: bartenderName, role: 'Fixed' }]
        };
        return [...next, newEntry];
      }
      return next;
    });
  }, [schedule]);

  const handleMoveAssignment = useCallback((
    from: { week: number, day: DayOfWeek, floor: string, bar: string },
    to: { week: number, day: DayOfWeek, floor: string, bar: string },
    bartenderName: string
  ) => {
    if (!schedule) return;

    // 1. Update Fixed Assignments
    setFixedAssignments(prev => {
      const filtered = prev.filter(fa => 
        !(fa.name === bartenderName && 
          parseInt(fa.week.split('_')[1]) === from.week && 
          fa.day === from.day && 
          (fa.floor || '').trim() === (from.floor || '').trim() && 
          (fa.bar || '').trim() === (from.bar || '').trim())
      );

      const newRule: FixedAssignment = {
        name: bartenderName,
        week: `Week_${to.week}` as any,
        day: to.day,
        floor: (to.floor || '').trim(),
        bar: (to.bar || '').trim()
      };

      return [...filtered, newRule];
    });

    // 2. Immediate UI Update
    setSchedule(prev => {
      if (!prev) return null;
      // Remove from original
      let next = prev.map(entry => {
        if (entry.week === from.week && entry.day === from.day && (entry.floor || '').trim() === (from.floor || '').trim() && (entry.bar || '').trim() === (from.bar || '').trim()) {
          return { ...entry, bartenders: entry.bartenders.filter(b => b.name !== bartenderName) };
        }
        return entry;
      });

      // Add to destination
      let foundTo = false;
      next = next.map(entry => {
        if (entry.week === to.week && entry.day === to.day && (entry.floor || '').trim() === (to.floor || '').trim() && (entry.bar || '').trim() === (to.bar || '').trim()) {
          foundTo = true;
          if (entry.bartenders.some(b => b.name === bartenderName)) return entry;
          return { ...entry, bartenders: [...entry.bartenders, { name: bartenderName, role: 'Fixed' }] };
        }
        return entry;
      });

      if (!foundTo) {
          next.push({
              week: to.week,
              day: to.day,
              floor: (to.floor || '').trim(),
              bar: (to.bar || '').trim(),
              bartenders: [{ name: bartenderName, role: 'Fixed' }]
          });
      }

      return next;
    });
  }, [schedule]);

  const scheduleTitle = useCallback(() => {
    if (!startDate) return 'Schedule';
    const dateObj = new Date(startDate + 'T00:00:00');
    if (generationMode === 'daily') return dateObj.toLocaleDateString(undefined, { weekday: 'long', month: 'short', day: 'numeric' });
    const startMonday = getMonday(dateObj);
    if (generationMode === 'weekly') return `Week of ${startMonday.toLocaleDateString()}`;
    const endDate = new Date(startMonday);
    endDate.setDate(endDate.getDate() + (weeksToGenerate * 7) - 1); 
    return `${startMonday.toLocaleDateString()} - ${endDate.toLocaleDateString()}`;
  }, [startDate, generationMode, weeksToGenerate])();

  const getEffectiveMondayDate = () => {
    if (!startDate) return undefined;
    const d = new Date(startDate + 'T00:00:00');
    const monday = getMonday(d);
    return `${monday.getFullYear()}-${String(monday.getMonth() + 1).padStart(2, '0')}-${String(monday.getDate()).padStart(2, '0')}`;
  };

  const effectiveStartDate = getEffectiveMondayDate();

  return (
    <div className="min-h-screen bg-slate-900 text-slate-200 font-sans p-4 sm:p-6 lg:p-8">
      <div className="max-w-screen-2xl mx-auto">
        <header className="mb-8">
          <h1 className="text-4xl sm:text-5xl font-bold text-white tracking-tight">
            AI Bartender Schedule Generator
          </h1>
          <p className="mt-2 text-lg text-slate-400">Smart logic for automated club scheduling.</p>
        </header>

        <main className="grid grid-cols-1 xl:grid-cols-4 xl:items-start gap-8">
          <aside className="xl:col-span-1 space-y-8 p-6 bg-slate-800/50 rounded-2xl border border-slate-700 shadow-lg xl:sticky xl:top-8 overflow-y-auto max-h-[calc(100vh-4rem)] custom-scrollbar">
            <div className="space-y-4 border-b border-slate-700 pb-6">
                <h3 className="text-base font-semibold text-slate-200">Schedule Mode</h3>
                <div className="flex bg-slate-900 rounded-lg p-1 border border-slate-600">
                    {['monthly', 'weekly', 'daily'].map((mode) => (
                      <button
                        key={mode}
                        onClick={() => setGenerationMode(mode as any)}
                        className={`flex-1 py-2 text-xs font-medium rounded-md transition-colors ${generationMode === mode ? 'bg-indigo-600 text-white shadow-sm' : 'text-slate-400 hover:text-slate-200'}`}
                      >
                        {mode.charAt(0).toUpperCase() + mode.slice(1)}
                      </button>
                    ))}
                </div>

                {generationMode !== 'daily' && (
                  <div>
                    <label className="block text-xs text-slate-400 mb-1">Number of Weeks</label>
                    <select 
                      value={weeksToGenerate}
                      onChange={(e) => setWeeksToGenerate(parseInt(e.target.value))}
                      className="w-full bg-slate-900/70 border border-slate-600 rounded-md py-2 px-3 text-sm text-slate-200"
                    >
                      {[1,2,3,4,5].map(n => <option key={n} value={n}>{n} Week{n > 1 ? 's' : ''}</option>)}
                    </select>
                  </div>
                )}

                <div>
                    <label className="block text-xs text-slate-400 mb-1">Start Date</label>
                    <div className="relative">
                        <CalendarIcon className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-slate-400 pointer-events-none"/>
                        <input type="date" value={startDate} onChange={(e) => setStartDate(e.target.value)} className="w-full bg-slate-900/70 border border-slate-600 rounded-md py-2 pl-9 text-sm text-slate-200 focus:ring-1 focus:ring-indigo-500" />
                    </div>
                </div>
            </div>

            {generationMode === 'daily' && getSpecificDay() && (
                 <DailyOverrideManager dailyOverrides={dailyOverrides} setDailyOverrides={setDailyOverrides} bartenders={bartenders} shifts={SHIFTS_TEMPLATE} specificDay={getSpecificDay()!} />
            )}

            <BartenderManager bartenders={bartenders} setBartenders={setBartenders} />
            <WeeklyAvailabilityManager bartenders={bartenders} setBartenders={setBartenders} />
            <FixedShiftManager fixedAssignments={fixedAssignments} setFixedAssignments={setFixedAssignments} bartenders={bartenders} shifts={SHIFTS_TEMPLATE} />
            <TimeOffRequestManager timeOffRequests={timeOffRequests} setTimeOffRequests={setTimeOffRequests} bartenders={bartenders} />
            <TargetShiftsManager targetShifts={targetShifts} setTargetShifts={setTargetShifts} />
            <EventShiftManager closedShifts={closedShifts} setClosedShifts={setClosedShifts} shifts={SHIFTS_TEMPLATE} />

            <div className="pt-4 border-t border-slate-700 space-y-3">
              <button
                onClick={handlePreviewFixed}
                disabled={isLoading}
                className="w-full flex items-center justify-center gap-2 bg-slate-700 text-slate-100 font-semibold py-2.5 px-4 rounded-lg hover:bg-slate-600 transition-colors"
              >
                <EyeIcon className="h-5 w-5" />
                Preview Fixed Only
              </button>
              <button
                onClick={handleGenerateSchedule}
                disabled={isLoading}
                className="w-full flex items-center justify-center gap-2 bg-indigo-600 text-white font-bold py-3 px-4 rounded-lg hover:bg-indigo-500 disabled:bg-slate-600 transition-all shadow-[0_4px_12px_rgba(79,70,229,0.3)]"
              >
                {isLoading ? <span className="animate-pulse">{statusMsg || 'Working...'}</span> : <><CalendarIcon className="h-5 w-5" /> Generate Full Schedule</>}
              </button>
            </div>
          </aside>

          <section className="xl:col-span-3 p-6 bg-slate-800/50 rounded-2xl border border-slate-700 shadow-lg min-h-[80vh]">
            <div className="flex flex-col sm:flex-row justify-between sm:items-center mb-6 gap-4">
              <h2 className="text-2xl font-bold text-white uppercase tracking-wide">{scheduleTitle}</h2>
              {schedule && schedule.length > 0 && (
                <button onClick={() => exportScheduleToHtml(schedule, scheduleTitle, bartenders, EARNINGS_MAP, effectiveStartDate)} className="flex items-center gap-2 bg-slate-700 text-slate-200 py-2 px-4 rounded-lg hover:bg-slate-600 transition-colors">
                  <DownloadIcon className="h-5 w-5" /> Export HTML
                </button>
              )}
            </div>

            {error && <div className="bg-red-900/50 border border-red-700 text-red-300 px-4 py-3 rounded-lg mb-4">{error}</div>}

            <div className="space-y-8">
              {schedule && schedule.length > 0 ? (
                <>
                  <SummaryView schedule={schedule} bartenders={bartenders} earningsMap={EARNINGS_MAP} />
                  <FloorDistributionView schedule={schedule} bartenders={bartenders} />
                  <ScheduleView 
                    schedule={schedule} 
                    startDate={effectiveStartDate} 
                    onMoveAssignment={handleMoveAssignment}
                    onAssignBartender={handleAssignBartender}
                    bartenders={bartenders}
                  />
                </>
              ) : (
                 !isLoading && (
                  <div className="flex flex-col items-center justify-center min-h-[400px] text-center text-slate-500 border-2 border-dashed border-slate-700 rounded-xl">
                      <CalendarIcon className="h-12 w-12 mb-4 opacity-20"/>
                      <p className="text-lg font-medium">Ready to build your schedule.</p>
                      <p className="text-sm mt-1 max-w-sm">Use "Preview Fixed Only" to see your manual setup, or "Generate Full Schedule" to let the AI fill the blanks.</p>
                  </div>
                 )
              )}
              {isLoading && (
                  <div className="flex flex-col items-center justify-center min-h-[400px] text-center text-slate-500">
                    <div className="w-12 h-12 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mb-4"></div>
                    <p className="text-lg font-medium">{statusMsg || 'Generating schedule...'}</p>
                  </div>
              )}
            </div>
          </section>
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useMemo, useState, useEffect, useRef } from 'react';
import type { Schedule, DayOfWeek, ScheduledBartender, Bartender } from '../types';
import { PlusIcon } from './icons/PlusIcon';
import { TrashIcon } from './icons/TrashIcon';

interface ScheduleViewProps {
  schedule: Schedule;
  startDate?: string;
  bartenders?: Bartender[];
  onMoveAssignment?: (
    from: { week: number, day: DayOfWeek, floor: string, bar: string },
    to: { week: number, day: DayOfWeek, floor: string, bar: string },
    bartenderName: string
  ) => void;
  onAssignBartender?: (
    week: number, day: DayOfWeek, floor: string, bar: string, bartenderName: string | null
  ) => void;
}

const DAY_ORDER: DayOfWeek[] = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun', 'Sun_Night'];
const FLOOR_ORDER = ['Rooftop', 'Hip Hop', "2010's", "2000's"];

const ScheduleView: React.FC<ScheduleViewProps> = ({ schedule, startDate, onMoveAssignment, onAssignBartender, bartenders = [] }) => {
  const [dragOverCell, setDragOverCell] = useState<string | null>(null);
  const [editingCell, setEditingCell] = useState<string | null>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Close dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setEditingCell(null);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Group data and calculate weekly counts for badges
  const groupedData = useMemo(() => {
    if (!schedule.length) return [];
    const maxWeek = Math.max(...schedule.map(s => s.week));
    const weeks = Array.from({ length: maxWeek }, (_, i) => i + 1);

    return weeks.map(week => {
      const weekSchedule = schedule.filter(s => s.week === week);
      if (weekSchedule.length === 0) return null;

      const grid: Record<string, Record<string, ScheduledBartender[]>> = {};
      const daysSet = new Set<DayOfWeek>();

      weekSchedule.forEach(entry => {
        daysSet.add(entry.day);
        const floor = (entry.floor || '').trim();
        const bar = (entry.bar || '').trim();
        const key = `${floor} / ${bar}`;
        if (!grid[key]) grid[key] = {};
        grid[key][entry.day] = entry.bartenders;
      });

      const days = Array.from(daysSet).sort((a, b) => DAY_ORDER.indexOf(a) - DAY_ORDER.indexOf(b));

      // Calculate shift counts for this specific week
      const weeklyCounts: Record<string, number> = {};
      weekSchedule.forEach(entry => {
        entry.bartenders.forEach(b => {
            weeklyCounts[b.name] = (weeklyCounts[b.name] || 0) + 1;
        });
      });

      const uniqueKeys = Object.keys(grid).sort((a, b) => {
          const [floorA, barA] = a.split(' / ');
          const [floorB, barB] = b.split(' / ');
          const indexA = FLOOR_ORDER.indexOf(floorA);
          const indexB = FLOOR_ORDER.indexOf(floorB);
          if (indexA !== indexB) return (indexA === -1 ? 1 : indexB === -1 ? -1 : indexA - indexB);
          return (barA || '').localeCompare(barB || '');
      });

      return { week, grid, days, uniqueKeys, weeklyCounts };
    }).filter(w => w !== null);
  }, [schedule]);

  const getFormattedDate = (start: string, day: DayOfWeek, weekIndex: number) => {
    const date = new Date(start + 'T00:00:00');
    const dayIndex = DAY_ORDER.indexOf(day);
    const offset = dayIndex === 7 ? 6 : dayIndex; 
    date.setDate(date.getDate() + offset + ((weekIndex - 1) * 7));
    return `${day.replace('_', ' ')} ${date.getMonth() + 1}/${date.getDate()}`;
  }

  // Drag and Drop handlers
  const handleDragStart = (e: React.DragEvent, bartenderName: string, week: number, day: string, floor: string, bar: string) => {
    const dragData = { name: bartenderName, from: { week, day, floor, bar } };
    e.dataTransfer.setData('application/json', JSON.stringify(dragData));
    e.dataTransfer.effectAllowed = 'move';
  };

  const handleDragOver = (e: React.DragEvent, cellKey: string) => {
    e.preventDefault();
    setDragOverCell(cellKey);
  };

  const handleDrop = (e: React.DragEvent, week: number, day: DayOfWeek, floor: string, bar: string) => {
    e.preventDefault();
    setDragOverCell(null);
    try {
        const data = JSON.parse(e.dataTransfer.getData('application/json'));
        if (onMoveAssignment && data.from && data.name) {
            onMoveAssignment(data.from, { week, day, floor, bar }, data.name);
        }
    } catch (err) {
        console.error("Failed to parse drag data", err);
    }
  };

  const toggleEditing = (cellKey: string) => {
    setEditingCell(prev => prev === cellKey ? null : cellKey);
  }

  const handleQuickAssign = (week: number, day: DayOfWeek, floor: string, bar: string, name: string | null) => {
    if (onAssignBartender) {
      onAssignBartender(week, day, floor, bar, name);
    }
    setEditingCell(null);
  }

  return (
    <div className="space-y-8 select-none overflow-hidden">
      {groupedData.map(({ week, grid, days, uniqueKeys, weeklyCounts }) => (
        <div key={week} className="animate-fadeIn">
          <div className="flex items-center gap-3 mb-4 px-1">
             <h3 className="text-xl font-bold text-white bg-indigo-600/20 px-4 py-1 rounded-full border border-indigo-500/30">Week {week}</h3>
             <div className="h-[1px] flex-1 bg-slate-700/50"></div>
          </div>
          <div className="overflow-x-auto rounded-xl border border-slate-700/50 bg-slate-800/30 shadow-inner max-h-[800px] custom-scrollbar">
            <table className="w-full min-w-[900px] text-sm text-left border-separate border-spacing-0">
              <thead className="text-xs text-slate-400 uppercase bg-slate-900/50 sticky top-0 z-[30]">
                <tr>
                  <th className="px-6 py-4 font-bold border-r border-b border-slate-700/50 bg-slate-900 sticky left-0 z-[40]">Shift</th>
                  {days.map(day => (
                    <th key={day} className="px-6 py-4 text-center border-b border-slate-700/50 bg-slate-900">
                      {startDate ? getFormattedDate(startDate, day as DayOfWeek, week) : day.replace('_', ' ')}
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-700/50">
                {uniqueKeys.map((key, rowIndex) => {
                  const [floor, bar] = key.split(' / ');
                  return (
                    <tr key={key} className="hover:bg-slate-700/10 transition-colors group">
                      <td className="px-6 py-4 border-r border-slate-700/50 font-medium sticky left-0 z-[20] bg-slate-800 group-hover:bg-slate-700 transition-colors shadow-[2px_0_5px_rgba(0,0,0,0.2)]">
                        <div className="font-bold text-slate-200 group-hover:text-indigo-300 transition-colors">{floor}</div>
                        <div className="text-[10px] uppercase tracking-wider text-slate-500 font-medium">{bar}</div>
                      </td>
                      {days.map(day => {
                        const cellBartenders = grid[key][day] || [];
                        const cellKey = `${week}-${key}-${day}`;
                        const isOver = dragOverCell === cellKey;
                        const isEditing = editingCell === cellKey;

                        // Dropdown direction logic
                        const isLastRows = rowIndex > uniqueKeys.length - 4;

                        return (
                          <td 
                            key={day} 
                            className={`px-6 py-4 text-center align-top transition-all duration-150 cursor-pointer relative border-b border-slate-700/30 ${isOver ? 'bg-indigo-600/30 shadow-[inset_0_0_12px_rgba(79,70,229,0.3)]' : 'hover:bg-slate-700/20'}`}
                            onDragOver={(e) => handleDragOver(e, cellKey)}
                            onDragLeave={() => setDragOverCell(null)}
                            onDrop={(e) => handleDrop(e, week, day as DayOfWeek, floor, bar)}
                            onClick={(e) => {
                                e.preventDefault();
                                toggleEditing(cellKey);
                            }}
                          >
                            <div className="absolute top-2 right-2 opacity-0 group-hover:opacity-40 transition-opacity">
                                <PlusIcon className="w-4 h-4 text-slate-400" />
                            </div>

                            {cellBartenders.length > 0 ? (
                              <div className="space-y-3 pointer-events-none">
                                {cellBartenders.map((b, idx) => (
                                  <div 
                                    key={idx} 
                                    draggable
                                    onDragStart={(e) => {
                                        e.stopPropagation(); 
                                        handleDragStart(e, b.name, week, day, floor, bar);
                                    }}
                                    className="flex flex-col items-center cursor-grab active:cursor-grabbing hover:brightness-125 transition-all duration-150 pointer-events-auto"
                                    onClick={(e) => e.stopPropagation()} 
                                  >
                                    <div className="flex items-center gap-1.5 relative group/name">
                                        <span className={`font-semibold text-sm ${b.role === 'Fixed' ? 'text-amber-400' : 'text-slate-200'}`}>
                                            {b.name}
                                        </span>
                                        <span 
                                            className="text-[10px] bg-slate-900/80 text-indigo-400 font-bold px-1.5 py-0 rounded-full border border-indigo-500/30 shadow-sm" 
                                            title={`Total shifts this week for ${b.name}`}
                                        >
                                            {weeklyCounts[b.name] || 0}
                                        </span>
                                    </div>
                                    {b.role && (
                                      <span className={`text-[9px] mt-1 uppercase font-bold px-1.5 py-0.5 rounded ${b.role === 'Fixed' ? 'bg-amber-900/40 text-amber-500 border border-amber-800/50' : 'bg-indigo-900/40 text-indigo-400 border border-indigo-800/50'}`}>
                                        {b.role}
                                      </span>
                                    )}
                                  </div>
                                ))}
                              </div>
                            ) : (
                              <div className="py-2 pointer-events-none">
                                <span className="text-[10px] font-bold text-slate-600 uppercase tracking-widest bg-slate-900/10 px-3 py-1.5 rounded-md border border-slate-700/20 block hover:border-slate-500/50 transition-colors">Open</span>
                              </div>
                            )}

                            {/* Floating Dropdown for Quick Assignment */}
                            {isEditing && (
                              <div 
                                ref={dropdownRef}
                                className={`fixed z-[100] transform -translate-x-1/2 mt-2 w-56 bg-slate-800 border border-slate-600 rounded-lg shadow-[0_15px_45px_rgba(0,0,0,0.8)] overflow-hidden animate-fadeIn`}
                                style={{
                                    left: '50%',
                                    top: isLastRows ? 'auto' : 'auto', // CSS positioning is handled by simple absolute/relative if not using a portal
                                }}
                                onClick={(e) => e.stopPropagation()}
                              >
                                <div className="p-3 border-b border-slate-700 bg-slate-900/90 text-[10px] uppercase font-bold text-slate-400 tracking-wider flex justify-between items-center">
                                  <span>Manage Shift</span>
                                  <span className="text-slate-600 text-[8px]">{day}</span>
                                </div>
                                <div className="max-h-80 overflow-y-auto custom-scrollbar bg-slate-800">
                                  <button 
                                    onClick={() => handleQuickAssign(week, day as DayOfWeek, floor, bar, null)}
                                    className="w-full text-left px-4 py-3 text-xs text-red-400 hover:bg-red-900/30 flex items-center gap-2 transition-colors border-b border-slate-700"
                                  >
                                    <TrashIcon className="w-4 h-4" /> Clear Cell
                                  </button>
                                  <div className="bg-slate-900/10 py-1">
                                    {bartenders.map(b => {
                                      const isCurrentlyAssigned = cellBartenders.some(cb => cb.name === b.name);
                                      return (
                                        <button 
                                          key={b.name}
                                          onClick={() => handleQuickAssign(week, day as DayOfWeek, floor, bar, b.name)}
                                          className={`w-full text-left px-4 py-3 text-sm transition-colors flex justify-between items-center ${isCurrentlyAssigned ? 'bg-indigo-900/40 text-indigo-300' : 'text-slate-200 hover:bg-indigo-600'}`}
                                        >
                                          <div className="flex items-center gap-2">
                                              <span className="font-medium">{b.name}</span>
                                              {isCurrentlyAssigned && <div className="w-2 h-2 rounded-full bg-indigo-400 shadow-[0_0_8px_rgba(129,140,248,0.5)]"></div>}
                                          </div>
                                          <span className="text-[10px] text-slate-500 font-mono bg-slate-900/40 px-1.5 rounded">T{b.tier}</span>
                                        </button>
                                      );
                                    })}
                                  </div>
                                </div>
                              </div>
                            )}
                          </td>
                        );
                      })}
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      ))}
    </div>
  );
};

export default ScheduleView;

import React, { useState, useCallback, useEffect } from 'react';
import type { Schedule, Bartender, FixedAssignment, TargetShifts, TimeOffRequest, ClosedShift, DayOfWeek, DailyOverride, ScheduleEntry } from './types';
import { BARTENDERS as initialBartenders, SHIFTS_TEMPLATE, FIXED_ASSIGNMENTS as initialFixedAssignments, EARNINGS_MAP } from './data';
import { generateSchedule, generateFixedOnlySchedule } from './services/schedulingAlgorithm';
import { exportScheduleToHtml } from './utils/scheduleExporter';
import ScheduleView from './components/ScheduleView';
import SummaryView from './components/SummaryView';
import BartenderManager from './components/BartenderManager';
import FixedShiftManager from './components/FixedShiftManager';
import WeeklyAvailabilityManager from './components/WeeklyAvailabilityManager';
import TimeOffRequestManager from './components/TimeOffRequestManager';
import TargetShiftsManager from './components/TargetShiftsManager';
import EventShiftManager from './components/EventShiftManager';
import DailyOverrideManager from './components/DailyOverrideManager';
import { DownloadIcon } from './components/icons/DownloadIcon';
import { CalendarIcon } from './components/icons/CalendarIcon';
import { EyeIcon } from './components/icons/EyeIcon';
import FloorDistributionView from './components/FloorDistributionView';

const App: React.FC = () => {
  // --- State Initialization with Persistence ---
  const [bartenders, setBartenders] = useState<Bartender[]>(() => {
    const saved = window.localStorage.getItem('bartenders');
    return saved ? JSON.parse(saved) : initialBartenders;
  });

  const [fixedAssignments, setFixedAssignments] = useState<FixedAssignment[]>(() => {
    const saved = window.localStorage.getItem('fixedAssignments');
    return saved ? JSON.parse(saved) : initialFixedAssignments;
  });

  const [timeOffRequests, setTimeOffRequests] = useState<TimeOffRequest[]>(() => {
    const saved = window.localStorage.getItem('timeOffRequests');
    return saved ? JSON.parse(saved) : [];
  });

  const [targetShifts, setTargetShifts] = useState<TargetShifts>(() => {
    const saved = window.localStorage.getItem('targetShifts');
    return saved ? JSON.parse(saved) : {};
  });

  const [closedShifts, setClosedShifts] = useState<ClosedShift[]>(() => {
    const saved = window.localStorage.getItem('closedShifts');
    return saved ? JSON.parse(saved) : [];
  });

  const [generationMode, setGenerationMode] = useState<'monthly' | 'weekly' | 'daily'>('monthly');
  const [weeksToGenerate, setWeeksToGenerate] = useState<number>(5);
  const [startDate, setStartDate] = useState<string>(() => {
    const d = new Date();
    d.setDate(d.getDate() + (1 + 7 - d.getDay()) % 7);
    return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
  });

  const [dailyOverrides, setDailyOverrides] = useState<DailyOverride[]>([]);
  const [schedule, setSchedule] = useState<Schedule | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [statusMsg, setStatusMsg] = useState<string | null>(null);

  useEffect(() => {
    if (generationMode === 'monthly') setWeeksToGenerate(5);
    else if (generationMode === 'weekly') setWeeksToGenerate(1);
  }, [generationMode]);

  useEffect(() => window.localStorage.setItem('bartenders', JSON.stringify(bartenders)), [bartenders]);
  useEffect(() => window.localStorage.setItem('fixedAssignments', JSON.stringify(fixedAssignments)), [fixedAssignments]);
  useEffect(() => window.localStorage.setItem('timeOffRequests', JSON.stringify(timeOffRequests)), [timeOffRequests]);
  useEffect(() => window.localStorage.setItem('targetShifts', JSON.stringify(targetShifts)), [targetShifts]);
  useEffect(() => window.localStorage.setItem('closedShifts', JSON.stringify(closedShifts)), [closedShifts]);

  const getMonday = (d: Date) => {
    const day = d.getDay();
    const diff = d.getDate() - day + (day === 0 ? -6 : 1);
    const monday = new Date(d);
    monday.setDate(diff);
    return monday;
  }

  const getSpecificDay = useCallback(() => {
    if (generationMode !== 'daily') return undefined;
    const d = new Date(startDate + 'T00:00:00');
    const dayMap: DayOfWeek[] = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
    return dayMap[d.getDay()];
  }, [startDate, generationMode]);

  const handlePreviewFixed = useCallback(() => {
    setIsLoading(true);
    setStatusMsg('Preparing fixed assignment preview...');
    setTimeout(() => {
      try {
        const generated = generateFixedOnlySchedule(
            SHIFTS_TEMPLATE,
            fixedAssignments,
            closedShifts,
            weeksToGenerate,
            getSpecificDay(),
            generationMode === 'daily' ? dailyOverrides : []
        );
        setSchedule(generated);
      } catch (err) {
        setError('Error generating preview.');
      } finally {
        setIsLoading(false);
        setStatusMsg(null);
      }
    }, 50);
  }, [fixedAssignments, closedShifts, generationMode, weeksToGenerate, dailyOverrides, getSpecificDay]);

  const handleGenerateSchedule = useCallback(() => {
    setIsLoading(true);
    setStatusMsg('AI is calculating optimal distribution...');
    setError(null);
    setTimeout(() => {
      try {
        const effectiveBaseDate = getEffectiveMondayDate() || startDate;
        const generatedSchedule = generateSchedule(
            bartenders, 
            SHIFTS_TEMPLATE, 
            fixedAssignments, 
            targetShifts, 
            timeOffRequests, 
            closedShifts,
            weeksToGenerate,
            getSpecificDay(),
            generationMode === 'daily' ? dailyOverrides : [],
            effectiveBaseDate
        );
        setSchedule(generatedSchedule);
      } catch (err) {
        setError(err instanceof Error ? err.message : 'An error occurred.');
      } finally {
        setIsLoading(false);
        setStatusMsg(null);
      }
    }, 50);
  }, [bartenders, fixedAssignments, targetShifts, timeOffRequests, closedShifts, generationMode, weeksToGenerate, dailyOverrides, getSpecificDay, startDate]);

  const handleAssignBartender = useCallback((
    week: number, day: DayOfWeek, floor: string, bar: string, bartenderName: string | null
  ) => {
    if (!schedule) return;

    // Normalize strings for safety
    const nFloor = (floor || '').trim();
    const nBar = (bar || '').trim();

    // 1. Update Fixed Assignments State
    setFixedAssignments(prev => {
      if (!bartenderName) {
        return prev.filter(fa => 
          !(parseInt(fa.week.split('_')[1]) === week && 
            fa.day === day && 
            (fa.floor || '').trim() === nFloor && 
            (fa.bar || '').trim() === nBar)
        );
      }

      const isAlreadyAssigned = prev.some(fa => 
        fa.name === bartenderName && 
        parseInt(fa.week.split('_')[1]) === week && 
        fa.day === day && 
        (fa.floor || '').trim() === nFloor && 
        (fa.bar || '').trim() === nBar
      );

      if (isAlreadyAssigned) {
        return prev.filter(fa => 
          !(fa.name === bartenderName && 
            parseInt(fa.week.split('_')[1]) === week && 
            fa.day === day && 
            (fa.floor || '').trim() === nFloor && 
            (fa.bar || '').trim() === nBar)
        );
      }

      const newRule: FixedAssignment = {
        name: bartenderName,
        week: `Week_${week}` as any,
        day: day,
        floor: nFloor,
        bar: nBar
      };
      return [...prev, newRule];
    });

    // 2. Immediate UI Update
    setSchedule(prev => {
      if (!prev) return null;
      let found = false;
      const next = prev.map(entry => {
        if (entry.week === week && entry.day === day && (entry.floor || '').trim() === nFloor && (entry.bar || '').trim() === nBar) {
          found = true;
          if (!bartenderName) return { ...entry, bartenders: [] };
          const isAlreadyInScheduleCell = entry.bartenders.some(b => b.name === bartenderName);
          if (isAlreadyInScheduleCell) {
             return { ...entry, bartenders: entry.bartenders.filter(b => b.name !== bartenderName) };
          }
          return { ...entry, bartenders: [...entry.bartenders, { name: bartenderName, role: 'Fixed' }] };
        }
        return entry;
      });

      if (!found && bartenderName) {
        const newEntry: ScheduleEntry = {
            week,
            day,
            floor: nFloor,
            bar: nBar,
            bartenders: [{ name: bartenderName, role: 'Fixed' }]
        };
        return [...next, newEntry];
      }
      return next;
    });
  }, [schedule]);

  const handleMoveAssignment = useCallback((
    from: { week: number, day: DayOfWeek, floor: string, bar: string },
    to: { week: number, day: DayOfWeek, floor: string, bar: string },
    bartenderName: string
  ) => {
    if (!schedule) return;

    // 1. Update Fixed Assignments
    setFixedAssignments(prev => {
      const filtered = prev.filter(fa => 
        !(fa.name === bartenderName && 
          parseInt(fa.week.split('_')[1]) === from.week && 
          fa.day === from.day && 
          (fa.floor || '').trim() === (from.floor || '').trim() && 
          (fa.bar || '').trim() === (from.bar || '').trim())
      );

      const newRule: FixedAssignment = {
        name: bartenderName,
        week: `Week_${to.week}` as any,
        day: to.day,
        floor: (to.floor || '').trim(),
        bar: (to.bar || '').trim()
      };

      return [...filtered, newRule];
    });

    // 2. Immediate UI Update
    setSchedule(prev => {
      if (!prev) return null;
      let next = prev.map(entry => {
        if (entry.week === from.week && entry.day === from.day && (entry.floor || '').trim() === (from.floor || '').trim() && (entry.bar || '').trim() === (from.bar || '').trim()) {
          return { ...entry, bartenders: entry.bartenders.filter(b => b.name !== bartenderName) };
        }
        return entry;
      });

      let foundTo = false;
      next = next.map(entry => {
        if (entry.week === to.week && entry.day === to.day && (entry.floor || '').trim() === (to.floor || '').trim() && (entry.bar || '').trim() === (to.bar || '').trim()) {
          foundTo = true;
          if (entry.bartenders.some(b => b.name === bartenderName)) return entry;
          return { ...entry, bartenders: [...entry.bartenders, { name: bartenderName, role: 'Fixed' }] };
        }
        return entry;
      });

      if (!foundTo) {
          next.push({
              week: to.week,
              day: to.day,
              floor: (to.floor || '').trim(),
              bar: (to.bar || '').trim(),
              bartenders: [{ name: bartenderName, role: 'Fixed' }]
          });
      }

      return next;
    });
  }, [schedule]);

  const getEffectiveMondayDate = () => {
    if (!startDate) return undefined;
    const d = new Date(startDate + 'T00:00:00');
    const monday = getMonday(d);
    return `${monday.getFullYear()}-${String(monday.getMonth() + 1).padStart(2, '0')}-${String(monday.getDate()).padStart(2, '0')}`;
  };

  const effectiveStartDate = getEffectiveMondayDate();

  const scheduleTitle = useCallback(() => {
    if (!startDate) return 'Schedule';
    const dateObj = new Date(startDate + 'T00:00:00');
    if (generationMode === 'daily') return dateObj.toLocaleDateString(undefined, { weekday: 'long', month: 'short', day: 'numeric' });
    const startMonday = getMonday(dateObj);
    if (generationMode === 'weekly') return `Week of ${startMonday.toLocaleDateString()}`;
    const endDate = new Date(startMonday);
    endDate.setDate(endDate.getDate() + (weeksToGenerate * 7) - 1); 
    return `${startMonday.toLocaleDateString()} - ${endDate.toLocaleDateString()}`;
  }, [startDate, generationMode, weeksToGenerate])();

  return (
    <div className="min-h-screen bg-slate-900 text-slate-200 font-sans p-4 sm:p-6 lg:p-8">
      <div className="max-w-screen-2xl mx-auto">
        <header className="mb-8">
          <h1 className="text-4xl sm:text-5xl font-bold text-white tracking-tight">
            AI Bartender Schedule Generator
          </h1>
          <p className="mt-2 text-lg text-slate-400">Smart logic for automated club scheduling.</p>
        </header>

        <main className="grid grid-cols-1 xl:grid-cols-4 xl:items-start gap-8">
          <aside className="xl:col-span-1 space-y-8 p-6 bg-slate-800/50 rounded-2xl border border-slate-700 shadow-lg xl:sticky xl:top-8 overflow-y-auto max-h-[calc(100vh-4rem)] custom-scrollbar">
            <div className="space-y-4 border-b border-slate-700 pb-6">
                <h3 className="text-base font-semibold text-slate-200">Schedule Mode</h3>
                <div className="flex bg-slate-900 rounded-lg p-1 border border-slate-600">
                    {['monthly', 'weekly', 'daily'].map((mode) => (
                      <button
                        key={mode}
                        onClick={() => setGenerationMode(mode as any)}
                        className={`flex-1 py-2 text-xs font-medium rounded-md transition-colors ${generationMode === mode ? 'bg-indigo-600 text-white shadow-sm' : 'text-slate-400 hover:text-slate-200'}`}
                      >
                        {mode.charAt(0).toUpperCase() + mode.slice(1)}
                      </button>
                    ))}
                </div>

                {generationMode !== 'daily' && (
                  <div>
                    <label className="block text-xs text-slate-400 mb-1">Number of Weeks</label>
                    <select 
                      value={weeksToGenerate}
                      onChange={(e) => setWeeksToGenerate(parseInt(e.target.value))}
                      className="w-full bg-slate-900/70 border border-slate-600 rounded-md py-2 px-3 text-sm text-slate-200"
                    >
                      {[1,2,3,4,5].map(n => <option key={n} value={n}>{n} Week{n > 1 ? 's' : ''}</option>)}
                    </select>
                  </div>
                )}

                <div>
                    <label className="block text-xs text-slate-400 mb-1">Start Date</label>
                    <div className="relative">
                        <CalendarIcon className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-slate-400 pointer-events-none"/>
                        <input type="date" value={startDate} onChange={(e) => setStartDate(e.target.value)} className="w-full bg-slate-900/70 border border-slate-600 rounded-md py-2 pl-9 text-sm text-slate-200 focus:ring-1 focus:ring-indigo-500" />
                    </div>
                </div>
            </div>

            {generationMode === 'daily' && getSpecificDay() && (
                 <DailyOverrideManager dailyOverrides={dailyOverrides} setDailyOverrides={setDailyOverrides} bartenders={bartenders} shifts={SHIFTS_TEMPLATE} specificDay={getSpecificDay()!} />
            )}

            <BartenderManager bartenders={bartenders} setBartenders={setBartenders} />
            <WeeklyAvailabilityManager bartenders={bartenders} setBartenders={setBartenders} />
            <FixedShiftManager fixedAssignments={fixedAssignments} setFixedAssignments={setFixedAssignments} bartenders={bartenders} shifts={SHIFTS_TEMPLATE} />
            <TimeOffRequestManager timeOffRequests={timeOffRequests} setTimeOffRequests={setTimeOffRequests} bartenders={bartenders} />
            <TargetShiftsManager targetShifts={targetShifts} setTargetShifts={setTargetShifts} />
            <EventShiftManager closedShifts={closedShifts} setClosedShifts={setClosedShifts} shifts={SHIFTS_TEMPLATE} />

            <div className="pt-4 border-t border-slate-700 space-y-3">
              <button
                onClick={handlePreviewFixed}
                disabled={isLoading}
                className="w-full flex items-center justify-center gap-2 bg-slate-700 text-slate-100 font-semibold py-2.5 px-4 rounded-lg hover:bg-slate-600 transition-colors"
              >
                <EyeIcon className="h-5 w-5" />
                Preview Fixed Only
              </button>
              <button
                onClick={handleGenerateSchedule}
                disabled={isLoading}
                className="w-full flex items-center justify-center gap-2 bg-indigo-600 text-white font-bold py-3 px-4 rounded-lg hover:bg-indigo-500 disabled:bg-slate-600 transition-all shadow-[0_4px_12px_rgba(79,70,229,0.3)]"
              >
                {isLoading ? <span className="animate-pulse">{statusMsg || 'Working...'}</span> : <><CalendarIcon className="h-5 w-5" /> Generate Full Schedule</>}
              </button>
            </div>
          </aside>

          <section className="xl:col-span-3 p-6 bg-slate-800/50 rounded-2xl border border-slate-700 shadow-lg min-h-[80vh]">
            <div className="flex flex-col sm:flex-row justify-between sm:items-center mb-6 gap-4">
              <h2 className="text-2xl font-bold text-white uppercase tracking-wide">{scheduleTitle}</h2>
              {schedule && schedule.length > 0 && (
                <button onClick={() => exportScheduleToHtml(schedule, scheduleTitle, bartenders, EARNINGS_MAP, effectiveStartDate)} className="flex items-center gap-2 bg-slate-700 text-slate-200 py-2 px-4 rounded-lg hover:bg-slate-600 transition-colors">
                  <DownloadIcon className="h-5 w-5" /> Export HTML
                </button>
              )}
            </div>

            {error && <div className="bg-red-900/50 border border-red-700 text-red-300 px-4 py-3 rounded-lg mb-4">{error}</div>}

            <div className="space-y-8">
              {schedule && schedule.length > 0 ? (
                <>
                  <SummaryView schedule={schedule} bartenders={bartenders} earningsMap={EARNINGS_MAP} />
                  <FloorDistributionView schedule={schedule} bartenders={bartenders} />
                  <ScheduleView 
                    schedule={schedule} 
                    startDate={effectiveStartDate} 
                    onMoveAssignment={handleMoveAssignment}
                    onAssignBartender={handleAssignBartender}
                    bartenders={bartenders}
                  />
                </>
              ) : (
                 !isLoading && (
                  <div className="flex flex-col items-center justify-center min-h-[400px] text-center text-slate-500 border-2 border-dashed border-slate-700 rounded-xl">
                      <CalendarIcon className="h-12 w-12 mb-4 opacity-20"/>
                      <p className="text-lg font-medium">Ready to build your schedule.</p>
                      <p className="text-sm mt-1 max-w-sm">Use "Preview Fixed Only" to see your manual setup, or "Generate Full Schedule" to let the AI fill the blanks.</p>
                  </div>
                 )
              )}
              {isLoading && (
                  <div className="flex flex-col items-center justify-center min-h-[400px] text-center text-slate-500">
                    <div className="w-12 h-12 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mb-4"></div>
                    <p className="text-lg font-medium">{statusMsg || 'Generating schedule...'}</p>
                  </div>
              )}
            </div>
          </section>
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useMemo, useState, useEffect, useRef } from 'react';
import type { Schedule, DayOfWeek, ScheduledBartender, Bartender } from '../types';
import { PlusIcon } from './icons/PlusIcon';
import { TrashIcon } from './icons/TrashIcon';

interface ScheduleViewProps {
  schedule: Schedule;
  startDate?: string;
  bartenders?: Bartender[];
  onMoveAssignment?: (
    from: { week: number, day: DayOfWeek, floor: string, bar: string },
    to: { week: number, day: DayOfWeek, floor: string, bar: string },
    bartenderName: string
  ) => void;
  onAssignBartender?: (
    week: number, day: DayOfWeek, floor: string, bar: string, bartenderName: string | null
  ) => void;
}

const DAY_ORDER: DayOfWeek[] = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun', 'Sun_Night'];
const FLOOR_ORDER = ['Rooftop', 'Hip Hop', "2010's", "2000's"];

const ScheduleView: React.FC<ScheduleViewProps> = ({ schedule, startDate, onMoveAssignment, onAssignBartender, bartenders = [] }) => {
  const [dragOverCell, setDragOverCell] = useState<string | null>(null);
  const [editingCell, setEditingCell] = useState<string | null>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Close dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setEditingCell(null);
      }
    };
    if (editingCell) {
        document.addEventListener('mousedown', handleClickOutside);
    }
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [editingCell]);

  const groupedData = useMemo(() => {
    if (!schedule.length) return [];
    const maxWeek = Math.max(...schedule.map(s => s.week));
    const weeks = Array.from({ length: maxWeek }, (_, i) => i + 1);

    return weeks.map(week => {
      const weekSchedule = schedule.filter(s => s.week === week);
      if (weekSchedule.length === 0) return null;

      const grid: Record<string, Record<string, ScheduledBartender[]>> = {};
      const daysSet = new Set<DayOfWeek>();

      weekSchedule.forEach(entry => {
        daysSet.add(entry.day);
        const floor = (entry.floor || '').trim();
        const bar = (entry.bar || '').trim();
        const key = `${floor} / ${bar}`;
        if (!grid[key]) grid[key] = {};
        grid[key][entry.day] = entry.bartenders;
      });

      const days = Array.from(daysSet).sort((a, b) => DAY_ORDER.indexOf(a) - DAY_ORDER.indexOf(b));

      const weeklyCounts: Record<string, number> = {};
      weekSchedule.forEach(entry => {
        entry.bartenders.forEach(b => {
            weeklyCounts[b.name] = (weeklyCounts[b.name] || 0) + 1;
        });
      });

      const uniqueKeys = Object.keys(grid).sort((a, b) => {
          const [floorA, barA] = a.split(' / ');
          const [floorB, barB] = b.split(' / ');
          const indexA = FLOOR_ORDER.indexOf(floorA);
          const indexB = FLOOR_ORDER.indexOf(floorB);
          if (indexA !== indexB) return (indexA === -1 ? 1 : indexB === -1 ? -1 : indexA - indexB);
          return (barA || '').localeCompare(barB || '');
      });

      return { week, grid, days, uniqueKeys, weeklyCounts };
    }).filter(w => w !== null);
  }, [schedule]);

  const getFormattedDate = (start: string, day: DayOfWeek, weekIndex: number) => {
    const date = new Date(start + 'T00:00:00');
    const dayIndex = DAY_ORDER.indexOf(day);
    const offset = dayIndex === 7 ? 6 : dayIndex; 
    date.setDate(date.getDate() + offset + ((weekIndex - 1) * 7));
    return `${day.replace('_', ' ')} ${date.getMonth() + 1}/${date.getDate()}`;
  }

  const handleDragStart = (e: React.DragEvent, bartenderName: string, week: number, day: string, floor: string, bar: string) => {
    const dragData = { name: bartenderName, from: { week, day, floor, bar } };
    e.dataTransfer.setData('application/json', JSON.stringify(dragData));
    e.dataTransfer.effectAllowed = 'move';
  };

  const handleDragOver = (e: React.DragEvent, cellKey: string) => {
    e.preventDefault();
    setDragOverCell(cellKey);
  };

  const handleDrop = (e: React.DragEvent, week: number, day: DayOfWeek, floor: string, bar: string) => {
    e.preventDefault();
    setDragOverCell(null);
    try {
        const data = JSON.parse(e.dataTransfer.getData('application/json'));
        if (onMoveAssignment && data.from && data.name) {
            onMoveAssignment(data.from, { week, day, floor, bar }, data.name);
        }
    } catch (err) {
        console.error("Failed to parse drag data", err);
    }
  };

  const toggleEditing = (cellKey: string) => {
    setEditingCell(prev => prev === cellKey ? null : cellKey);
  }

  const handleQuickAssign = (week: number, day: DayOfWeek, floor: string, bar: string, name: string | null) => {
    if (onAssignBartender) {
      onAssignBartender(week, day, floor, bar, name);
    }
    setEditingCell(null);
  }

  return (
    <div className="space-y-8 select-none">
      {groupedData.map(({ week, grid, days, uniqueKeys, weeklyCounts }) => (
        <div key={week} className="animate-fadeIn">
          <div className="flex items-center gap-3 mb-4 px-1">
             <h3 className="text-xl font-bold text-white bg-indigo-600/20 px-4 py-1 rounded-full border border-indigo-500/30">Week {week}</h3>
             <div className="h-[1px] flex-1 bg-slate-700/50"></div>
          </div>
          <div className="overflow-x-auto rounded-xl border border-slate-700/50 bg-slate-800/30 shadow-inner max-h-[800px] custom-scrollbar">
            <table className="w-full min-w-[900px] text-sm text-left border-separate border-spacing-0">
              <thead className="text-xs text-slate-400 uppercase bg-slate-900 sticky top-0 z-[40]">
                <tr>
                  <th className="px-6 py-4 font-bold border-r border-b border-slate-700/50 bg-slate-900 sticky left-0 z-[50]">Shift</th>
                  {days.map(day => (
                    <th key={day} className="px-6 py-4 text-center border-b border-slate-700/50">
                      {startDate ? getFormattedDate(startDate, day as DayOfWeek, week) : day.replace('_', ' ')}
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-700/50">
                {uniqueKeys.map((key, rowIndex) => {
                  const [floor, bar] = key.split(' / ');
                  return (
                    <tr key={key} className="hover:bg-slate-700/10 transition-colors group">
                      <td className="px-6 py-4 border-r border-slate-700/50 font-medium sticky left-0 z-[30] bg-slate-800 group-hover:bg-slate-700 transition-colors shadow-[2px_0_5px_rgba(0,0,0,0.2)]">
                        <div className="font-bold text-slate-200 group-hover:text-indigo-300 transition-colors">{floor}</div>
                        <div className="text-[10px] uppercase tracking-wider text-slate-500 font-medium">{bar}</div>
                      </td>
                      {days.map(day => {
                        const cellBartenders = grid[key][day] || [];
                        const cellKey = `${week}-${key}-${day}`;
                        const isOver = dragOverCell === cellKey;
                        const isEditing = editingCell === cellKey;
                        const isLastRows = rowIndex > uniqueKeys.length - 4;

                        return (
                          <td 
                            key={day} 
                            className={`px-6 py-4 text-center align-top transition-all duration-150 cursor-pointer relative border-b border-slate-700/30 ${isOver ? 'bg-indigo-600/30 shadow-[inset_0_0_12px_rgba(79,70,229,0.3)]' : 'hover:bg-slate-700/20'} ${isEditing ? 'bg-indigo-900/10' : ''}`}
                            onDragOver={(e) => handleDragOver(e, cellKey)}
                            onDragLeave={() => setDragOverCell(null)}
                            onDrop={(e) => handleDrop(e, week, day as DayOfWeek, floor, bar)}
                            onClick={() => toggleEditing(cellKey)}
                          >
                            <div className="absolute top-2 right-2 opacity-0 group-hover:opacity-40 transition-opacity pointer-events-none">
                                <PlusIcon className="w-4 h-4 text-slate-400" />
                            </div>

                            {cellBartenders.length > 0 ? (
                              <div className="space-y-3">
                                {cellBartenders.map((b, idx) => (
                                  <div 
                                    key={idx} 
                                    draggable
                                    onDragStart={(e) => {
                                        e.stopPropagation(); 
                                        handleDragStart(e, b.name, week, day, floor, bar);
                                    }}
                                    className="flex flex-col items-center cursor-grab active:cursor-grabbing hover:brightness-125 transition-all duration-150"
                                    onClick={(e) => {
                                        // Allow triggering the menu from clicking names too
                                        // We don't stop propagation here to let the cell handle it
                                    }} 
                                  >
                                    <div className="flex items-center gap-1.5 relative group/name">
                                        <span className={`font-semibold text-sm ${b.role === 'Fixed' ? 'text-amber-400' : 'text-slate-200'}`}>
                                            {b.name}
                                        </span>
                                        <span 
                                            className="text-[10px] bg-slate-900/80 text-indigo-400 font-bold px-1.5 py-0 rounded-full border border-indigo-500/30 shadow-sm" 
                                        >
                                            {weeklyCounts[b.name] || 0}
                                        </span>
                                    </div>
                                    {b.role && (
                                      <span className={`text-[9px] mt-1 uppercase font-bold px-1.5 py-0.5 rounded ${b.role === 'Fixed' ? 'bg-amber-900/40 text-amber-500 border border-amber-800/50' : 'bg-indigo-900/40 text-indigo-400 border border-indigo-800/50'}`}>
                                        {b.role}
                                      </span>
                                    )}
                                  </div>
                                ))}
                              </div>
                            ) : (
                              <div className="py-2">
                                <span className="text-[10px] font-bold text-slate-600 uppercase tracking-widest bg-slate-900/10 px-3 py-1.5 rounded-md border border-slate-700/20 block">Open</span>
                              </div>
                            )}

                            {isEditing && (
                              <div 
                                ref={dropdownRef}
                                className={`absolute z-[100] left-1/2 -translate-x-1/2 ${isLastRows ? 'bottom-full mb-2' : 'top-full mt-2'} w-56 bg-slate-800 border border-slate-600 rounded-lg shadow-[0_15px_45px_rgba(0,0,0,0.8)] overflow-hidden animate-fadeIn`}
                                onClick={(e) => e.stopPropagation()}
                              >
                                <div className="p-3 border-b border-slate-700 bg-slate-900/90 text-[10px] uppercase font-bold text-slate-400 tracking-wider flex justify-between items-center">
                                  <span>Quick Assign</span>
                                  <span className="text-slate-600 text-[8px]">{day}</span>
                                </div>
                                <div className="max-h-80 overflow-y-auto custom-scrollbar bg-slate-800">
                                  <button 
                                    onClick={() => handleQuickAssign(week, day as DayOfWeek, floor, bar, null)}
                                    className="w-full text-left px-4 py-3 text-xs text-red-400 hover:bg-red-900/30 flex items-center gap-2 transition-colors border-b border-slate-700"
                                  >
                                    <TrashIcon className="w-4 h-4" /> Clear All Assignments
                                  </button>
                                  <div className="bg-slate-900/10 py-1">
                                    {bartenders.map(b => {
                                      const isCurrentlyAssigned = cellBartenders.some(cb => cb.name === b.name);
                                      return (
                                        <button 
                                          key={b.name}
                                          onClick={() => handleQuickAssign(week, day as DayOfWeek, floor, bar, b.name)}
                                          className={`w-full text-left px-4 py-3 text-sm transition-colors flex justify-between items-center ${isCurrentlyAssigned ? 'bg-indigo-900/40 text-indigo-300' : 'text-slate-200 hover:bg-indigo-600'}`}
                                        >
                                          <div className="flex items-center gap-2">
                                              <span className="font-medium">{b.name}</span>
                                              {isCurrentlyAssigned && <div className="w-2 h-2 rounded-full bg-indigo-400 shadow-[0_0_8px_rgba(129,140,248,0.5)]"></div>}
                                          </div>
                                          <span className="text-[10px] text-slate-500 font-mono bg-slate-900/40 px-1.5 rounded">T{b.tier}</span>
                                        </button>
                                      );
                                    })}
                                  </div>
                                </div>
                              </div>
                            )}
                          </td>
                        );
                      })}
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      ))}
    </div>
  );
};

